        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_conceito.grupo", "ly_conceito.conceito"
      });
            if (scColumns.Contains("nota")) list.Add("ly_conceito.nota");
            if (scColumns.Contains("descricao")) list.Add("ly_conceito.descricao");
            if (scColumns.Contains("valor_minimo")) list.Add("ly_conceito.valor_minimo");
            if (scColumns.Contains("valor_maximo")) list.Add("ly_conceito.valor_maximo");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_conceito " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_conceito");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_conceito");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["GRUPO"] != null && string.IsNullOrEmpty(dr["GRUPO"].ToString()))
                    dr["GRUPO"] = DBNull.Value;
                if (dr["CONCEITO"] != null && string.IsNullOrEmpty(dr["CONCEITO"].ToString()))
                    dr["CONCEITO"] = DBNull.Value;
                if (dr["NOTA"] != null && string.IsNullOrEmpty(dr["NOTA"].ToString()))
                    dr["NOTA"] = DBNull.Value;
                if (dr["DESCRICAO"] != null && string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                    dr["DESCRICAO"] = DBNull.Value;
                if (dr["VALOR_MINIMO"] != null && string.IsNullOrEmpty(dr["VALOR_MINIMO"].ToString()))
                    dr["VALOR_MINIMO"] = DBNull.Value;
                if (dr["VALOR_MAXIMO"] != null && string.IsNullOrEmpty(dr["VALOR_MAXIMO"].ToString()))
                    dr["VALOR_MAXIMO"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["GRUPO"] == null || string.IsNullOrEmpty(dr["GRUPO"].ToString()))
                {
                    return "Favor informar o grupo.";
                }

                if (dr["GRUPO"] != null && !string.IsNullOrEmpty(dr["GRUPO"].ToString()))
                {
                    if (dr["GRUPO"].ToString().Length > 20)
                    {
                        return "O grupo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["CONCEITO"] == null || string.IsNullOrEmpty(dr["CONCEITO"].ToString()))
                {
                    return "Favor informar o conceito.";
                }

                if (dr["CONCEITO"] != null && !string.IsNullOrEmpty(dr["CONCEITO"].ToString()))
                {
                    if (dr["CONCEITO"].ToString().Length > 15)
                    {
                        return "O conceito deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["NOTA"] == null || string.IsNullOrEmpty(dr["NOTA"].ToString()))
                {
                    return "Favor informar a nota.";
                }

                if (dr["NOTA"] != null && !string.IsNullOrEmpty(dr["NOTA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["NOTA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NOTA"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["NOTA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NOTA"]).ToString("0.############").Split(',')[1].Length > 4))
                    {
                        return "A nota deve ser um valor numérico com, no máximo, 3 dígitos na parte inteira e 4 casas decimal.";
                    }
                }

                if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    if (dr["DESCRICAO"].ToString().Length > 100)
                    {
                        return "A descriçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["VALOR_MINIMO"] == null || string.IsNullOrEmpty(dr["VALOR_MINIMO"].ToString()))
                {
                    return "Favor informar o valor mínimo.";
                }

                if (dr["VALOR_MINIMO"] != null && !string.IsNullOrEmpty(dr["VALOR_MINIMO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["VALOR_MINIMO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_MINIMO"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["VALOR_MINIMO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_MINIMO"]).ToString("0.############").Split(',')[1].Length > 4))
                    {
                        return "O valor mínimo deve ser um valor numérico com, no máximo, 3 dígitos na parte inteira e 4 casas decimal.";
                    }
                }

                if (dr["VALOR_MAXIMO"] == null || string.IsNullOrEmpty(dr["VALOR_MAXIMO"].ToString()))
                {
                    return "Favor informar o valor máximo.";
                }

                if (dr["VALOR_MAXIMO"] != null && !string.IsNullOrEmpty(dr["VALOR_MAXIMO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["VALOR_MAXIMO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_MAXIMO"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["VALOR_MAXIMO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["VALOR_MAXIMO"]).ToString("0.############").Split(',')[1].Length > 4))
                    {
                        return "O valor máximo deve ser um valor numérico com, no máximo, 3 dígitos na parte inteira e 4 casas decimal.";
                    }
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

