                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["UNIDADE_FIS"] != null && string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                    dr["UNIDADE_FIS"] = DBNull.Value;
                if (dr["CHAVE"] != null && string.IsNullOrEmpty(dr["CHAVE"].ToString()))
                    dr["CHAVE"] = DBNull.Value;
                if (dr["CONTATO_DESCR"] != null && string.IsNullOrEmpty(dr["CONTATO_DESCR"].ToString()))
                    dr["CONTATO_DESCR"] = DBNull.Value;
                if (dr["FONE"] != null && string.IsNullOrEmpty(dr["FONE"].ToString()))
                    dr["FONE"] = DBNull.Value;
                if (dr["COMPLEMENTO"] != null && string.IsNullOrEmpty(dr["COMPLEMENTO"].ToString()))
                    dr["COMPLEMENTO"] = DBNull.Value;
                if (dr["ATIVO"] != null && string.IsNullOrEmpty(dr["ATIVO"].ToString()))
                    dr["ATIVO"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["UNIDADE_FIS"] == null || string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                {
                    return "Favor informar a unidade física.";
                }

                if (dr["UNIDADE_FIS"] != null && !string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                {
                    if (dr["UNIDADE_FIS"].ToString().Length > 20)
                    {
                        return "A unidade física deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["CHAVE"] == null || string.IsNullOrEmpty(dr["CHAVE"].ToString()))
                {
                    return "Favor informar a chave.";
                }

                if (dr["CHAVE"] != null && !string.IsNullOrEmpty(dr["CHAVE"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A chave deve ser um valor inteiro com 3 dígitos no máximo.";
                    }
                }

                if (dr["CONTATO_DESCR"] == null || string.IsNullOrEmpty(dr["CONTATO_DESCR"].ToString()))
                {
                    return "Favor informar o contato.";
                }

                if (dr["CONTATO_DESCR"] != null && !string.IsNullOrEmpty(dr["CONTATO_DESCR"].ToString()))
                {
                    if (dr["CONTATO_DESCR"].ToString().Length > 100)
                    {
                        return "O contato deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["FONE"] != null && !string.IsNullOrEmpty(dr["FONE"].ToString()))
                {
                    if (dr["FONE"].ToString().Length > 30)
                    {
                        return "O telefone deve possuir no máximo 30 caracteres.";
                    }
                }

                if (dr["COMPLEMENTO"] != null && !string.IsNullOrEmpty(dr["COMPLEMENTO"].ToString()))
                {
                    if (dr["COMPLEMENTO"].ToString().Length > 50)
                    {
                        return "O complemento deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["ATIVO"] != null && !string.IsNullOrEmpty(dr["ATIVO"].ToString()))
                {
                    if (dr["ATIVO"].ToString().Length > 1)
                    {
                        return "O ativo deve possuir no máximo 1 caractere.";
                    }
                }
            }
            return "";
        }

