        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "pessoa") { result.Add(toLower ? "pessoa" : column); continue; }
                    if (lower == "chave") { result.Add(toLower ? "chave" : column); continue; }
                    if (lower == "tipo") { result.Add(toLower ? "tipo" : column); continue; }
                    if (lower == "dtini") { result.Add(toLower ? "dtini" : column); continue; }
                    if (lower == "dtfim") { result.Add(toLower ? "dtfim" : column); continue; }
                    if (lower == "grande_area") { result.Add(toLower ? "grande_area" : column); continue; }
                    if (lower == "area") { result.Add(toLower ? "area" : column); continue; }
                    if (lower == "titulacao") { result.Add(toLower ? "titulacao" : column); continue; }
                    if (lower == "outra_faculdade") { result.Add(toLower ? "outra_faculdade" : column); continue; }
                    if (lower == "entregou_doc") { result.Add(toLower ? "entregou_doc" : column); continue; }
                    if (lower == "titulo_projeto") { result.Add(toLower ? "titulo_projeto" : column); continue; }
                    if (!tabPrincipal)
                    {
                        if (lower == "nome_comp") { result.Add(toLower ? "nome_comp" : column); continue; }
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "chave", "tipo", "dtini", "dtfim", "grande_area", "area", 
                                           "titulacao", "outra_faculdade", "entregou_doc", "titulo_projeto" }
                                    : new string[] { "PESSOA", "CHAVE", "TIPO", "DTINI", "DTFIM", "GRANDE_AREA", "AREA", 
                                           "TITULACAO", "OUTRA_FACULDADE", "ENTREGOU_DOC", "TITULO_PROJETO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "chave", "tipo", "dtini", "dtfim", "grande_area", "area", 
                                           "titulacao", "outra_faculdade", "entregou_doc", "titulo_projeto", "nome_comp" }
                                    : new string[] { "PESSOA", "CHAVE", "TIPO", "DTINI", "DTFIM", "GRANDE_AREA", "AREA", 
                                           "TITULACAO", "OUTRA_FACULDADE", "ENTREGOU_DOC", "TITULO_PROJETO", "NOME_COMP" });

            return result;
        }


