        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["PESSOA"] == null || string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    return "Favor informar a pessoa.";
                }

                if (dr["PESSOA"] != null && !string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A pessoa deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["CHAVE"] == null || string.IsNullOrEmpty(dr["CHAVE"].ToString()))
                {
                    return "Favor informar a chave.";
                }

                if (dr["CHAVE"] != null && !string.IsNullOrEmpty(dr["CHAVE"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHAVE"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A chave deve ser um valor inteiro com 3 dígitos no máximo.";
                    }
                }

                if (dr["TIPO"] == null || string.IsNullOrEmpty(dr["TIPO"].ToString()))
                {
                    return "Favor informar o tipo.";
                }

                if (dr["TIPO"] != null && !string.IsNullOrEmpty(dr["TIPO"].ToString()))
                {
                    if (dr["TIPO"].ToString().Length > 20)
                    {
                        return "O tipo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DTINI"] == null || string.IsNullOrEmpty(dr["DTINI"].ToString()))
                {
                    return "Favor informar a data de início.";
                }

                if (dr["DTINI"] != null && dr["DTINI"].ToString() != "")
                {
                    dr["DTINI"] = Convert.ToDateTime(dr["DTINI"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["DTFIM"] != null && dr["DTFIM"].ToString() != "")
                {
                    dr["DTFIM"] = Convert.ToDateTime(dr["DTFIM"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["GRANDE_AREA"] != null && !string.IsNullOrEmpty(dr["GRANDE_AREA"].ToString()))
                {
                    if (dr["GRANDE_AREA"].ToString().Length > 40)
                    {
                        return "A grande área deve possuir no máximo 40 caracteres.";
                    }
                }

                if (dr["AREA"] != null && !string.IsNullOrEmpty(dr["AREA"].ToString()))
                {
                    if (dr["AREA"].ToString().Length > 100)
                    {
                        return "A área deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["TITULACAO"] == null || string.IsNullOrEmpty(dr["TITULACAO"].ToString()))
                {
                    return "Favor informar a titulaçăo.";
                }

                if (dr["TITULACAO"] != null && !string.IsNullOrEmpty(dr["TITULACAO"].ToString()))
                {
                    if (dr["TITULACAO"].ToString().Length > 20)
                    {
                        return "A titulaçăo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["OUTRA_FACULDADE"] == null || string.IsNullOrEmpty(dr["OUTRA_FACULDADE"].ToString()))
                {
                    return "Favor informar a instituiçăo.";
                }

                if (dr["OUTRA_FACULDADE"] != null && !string.IsNullOrEmpty(dr["OUTRA_FACULDADE"].ToString()))
                {
                    if (dr["OUTRA_FACULDADE"].ToString().Length > 20)
                    {
                        return "A instituiçăo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["ENTREGOU_DOC"] != null && !string.IsNullOrEmpty(dr["ENTREGOU_DOC"].ToString()))
                {
                    if (dr["ENTREGOU_DOC"].ToString().Length > 1)
                    {
                        return "O entregou docuemntos? deve possuir no máximo 1 caractere.";
                    }

                    if (dr["ENTREGOU_DOC"] != null && !string.IsNullOrEmpty(dr["ENTREGOU_DOC"].ToString()))
                    {
                        List<object> lstENTREGOU_DOC = new List<object>(new object[] { "S", "N" });
                        if (!lstENTREGOU_DOC.Contains(dr["ENTREGOU_DOC"].ToString()))
                        {
                            return "Os valores permitidos para o entregou docuemntos? săo ''S'' ou ''N''.";
                        }
                    }
                }

                if (dr["TITULO_PROJETO"] != null && !string.IsNullOrEmpty(dr["TITULO_PROJETO"].ToString()))
                {
                    if (dr["TITULO_PROJETO"].ToString().Length > 500)
                    {
                        return "O Titulo_projeto deve possuir no máximo 500 caracteres.";
                    }
                }
            }
            return "";
        }

