        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_depto.faculdade", "ly_depto.depto"
      });
            if (scColumns.Contains("nome")) list.Add("ly_depto.nome");
            if (scColumns.Contains("outra_faculdade")) list.Add("ly_depto.outra_faculdade");
            if (scColumns.Contains("observacao")) list.Add("ly_depto.observacao");
            if (scColumns.Contains("imagem")) list.Add("ly_depto.imagem");
            if (scColumns.Contains("nome_comp")) list.Add("ly_unidade_ensino.nome_comp");
            if (scColumns.Contains("nome_abrev")) list.Add("ly_unidade_ensino.nome_abrev");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_depto " +
                     "INNER JOIN ly_unidade_ensino " +
                       "ON ly_unidade_ensino.unidade_ens = ly_depto.faculdade " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_depto");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_depto");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["FACULDADE"] != null && string.IsNullOrEmpty(dr["FACULDADE"].ToString()))
                    dr["FACULDADE"] = DBNull.Value;
                if (dr["DEPTO"] != null && string.IsNullOrEmpty(dr["DEPTO"].ToString()))
                    dr["DEPTO"] = DBNull.Value;
                if (dr["NOME"] != null && string.IsNullOrEmpty(dr["NOME"].ToString()))
                    dr["NOME"] = DBNull.Value;
                if (dr["OUTRA_FACULDADE"] != null && string.IsNullOrEmpty(dr["OUTRA_FACULDADE"].ToString()))
                    dr["OUTRA_FACULDADE"] = DBNull.Value;
                if (dr["OBSERVACAO"] != null && string.IsNullOrEmpty(dr["OBSERVACAO"].ToString()))
                    dr["OBSERVACAO"] = DBNull.Value;
                if (dr["IMAGEM"] != null && string.IsNullOrEmpty(dr["IMAGEM"].ToString()))
                    dr["IMAGEM"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["FACULDADE"] == null || string.IsNullOrEmpty(dr["FACULDADE"].ToString()))
                {
                    return "Favor informar a unidade.";
                }

                if (dr["FACULDADE"] != null && !string.IsNullOrEmpty(dr["FACULDADE"].ToString()))
                {
                    if (dr["FACULDADE"].ToString().Length > 20)
                    {
                        return "A unidade deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DEPTO"] == null || string.IsNullOrEmpty(dr["DEPTO"].ToString()))
                {
                    return "Favor informar o departamento.";
                }

                if (dr["DEPTO"] != null && !string.IsNullOrEmpty(dr["DEPTO"].ToString()))
                {
                    if (dr["DEPTO"].ToString().Length > 20)
                    {
                        return "O departamento deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["NOME"] != null && !string.IsNullOrEmpty(dr["NOME"].ToString()))
                {
                    if (dr["NOME"].ToString().Length > 100)
                    {
                        return "O nome do departamento deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["OUTRA_FACULDADE"] != null && !string.IsNullOrEmpty(dr["OUTRA_FACULDADE"].ToString()))
                {
                    if (dr["OUTRA_FACULDADE"].ToString().Length > 20)
                    {
                        return "O Outra_faculdade deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["OBSERVACAO"] != null && !string.IsNullOrEmpty(dr["OBSERVACAO"].ToString()))
                {
                    if (dr["OBSERVACAO"].ToString().Length > 100)
                    {
                        return "O Observacao deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["IMAGEM"] != null && !string.IsNullOrEmpty(dr["IMAGEM"].ToString()))
                {
                    if (dr["IMAGEM"].ToString().Length > 100)
                    {
                        return "O Imagem deve possuir no máximo 100 caracteres.";
                    }
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

