        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_docente.num_func"
      });

            if (scColumns.Contains("senha_dol")) list.Add("ly_docente.senha_dol");
            if (scColumns.Contains("categoria")) list.Add("ly_docente.categoria");
            if (scColumns.Contains("dt_admissao")) list.Add("ly_docente.dt_admissao");
            if (scColumns.Contains("pessoa")) list.Add("ly_docente.pessoa");
            if (scColumns.Contains("regime_trabalho")) list.Add("ly_docente.regime_trabalho");
            if (scColumns.Contains("dt_demissao")) list.Add("ly_docente.dt_demissao");
            if (scColumns.Contains("stamp_atualizacao")) list.Add("ly_docente.stamp_atualizacao");
            if (scColumns.Contains("matricula")) list.Add("ly_docente.matricula");
            if (scColumns.Contains("senha_alterada")) list.Add("ly_docente.senha_alterada");
            if (scColumns.Contains("ano_ingresso")) list.Add("ly_docente.ano_ingresso");
            if (scColumns.Contains("concurso")) list.Add("ly_docente.concurso");
            if (scColumns.Contains("candidato")) list.Add("ly_docente.candidato");
            if (scColumns.Contains("voluntario")) list.Add("ly_docente.voluntario");
            if (scColumns.Contains("REGIMECONTRATACAOID")) list.Add("ly_docente.REGIMECONTRATACAOID");
            if (scColumns.Contains("ACUMULACAO")) list.Add("ly_docente.ACUMULACAO");
            if (scColumns.Contains("vinculo")) list.Add("ly_docente.vinculo");
            if (scColumns.Contains("usuario")) list.Add("ly_docente.usuario");
            if (scColumns.Contains("datacadastro")) list.Add("ly_docente.datacadastro");
            if (scColumns.Contains("dataalteracao")) list.Add("ly_docente.dataalteracao");

            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_docente " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_docente");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_docente");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["NUM_FUNC"] != null && string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                    dr["NUM_FUNC"] = DBNull.Value;
                if (dr["SENHA_DOL"] != null && string.IsNullOrEmpty(dr["SENHA_DOL"].ToString()))
                    dr["SENHA_DOL"] = DBNull.Value;
                if (dr["CATEGORIA"] != null && string.IsNullOrEmpty(dr["CATEGORIA"].ToString()))
                    dr["CATEGORIA"] = DBNull.Value;
                if (dr["PESSOA"] != null && string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                    dr["PESSOA"] = DBNull.Value;              
                if (dr["REGIME_TRABALHO"] != null && string.IsNullOrEmpty(dr["REGIME_TRABALHO"].ToString()))
                    dr["REGIME_TRABALHO"] = DBNull.Value;
                if (dr["MATRICULA"] != null && string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                    dr["MATRICULA"] = DBNull.Value;
                if (dr["SENHA_ALTERADA"] != null && string.IsNullOrEmpty(dr["SENHA_ALTERADA"].ToString()))
                    dr["SENHA_ALTERADA"] = DBNull.Value;
                if (dr["ANO_INGRESSO"] != null && string.IsNullOrEmpty(dr["ANO_INGRESSO"].ToString()))
                    dr["ANO_INGRESSO"] = DBNull.Value;
                if (dr["CONCURSO"] != null && string.IsNullOrEmpty(dr["CONCURSO"].ToString()))
                    dr["CONCURSO"] = DBNull.Value;
                if (dr["CANDIDATO"] != null && string.IsNullOrEmpty(dr["CANDIDATO"].ToString()))
                    dr["CANDIDATO"] = DBNull.Value;
                if (dr["VOLUNTARIO"] != null && string.IsNullOrEmpty(dr["VOLUNTARIO"].ToString()))
                    dr["VOLUNTARIO"] = DBNull.Value;
                if (dr["USUARIO"] != null && string.IsNullOrEmpty(dr["USUARIO"].ToString()))
                    dr["USUARIO"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["NUM_FUNC"] == null || string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                {
                    return "Favor informar o código do funcionário.";
                }

                if (dr["NUM_FUNC"] != null && !string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',')[0].Length > 15) || (Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O código do funcionário deve ser um valor inteiro com 15 dígitos no máximo.";
                    }
                }

                if (dr["SENHA_DOL"] != null && !string.IsNullOrEmpty(dr["SENHA_DOL"].ToString()))
                {
                    if (dr["SENHA_DOL"].ToString().Length > 40)
                    {
                        return "O Senha_dol deve possuir no máximo 40 caracteres.";
                    }
                }
                if (dr["CATEGORIA"] != null && !string.IsNullOrEmpty(dr["CATEGORIA"].ToString()))
                {
                    if (dr["CATEGORIA"].ToString().Length > 20)
                    {
                        return "O cargo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DT_ADMISSAO"] != null && dr["DT_ADMISSAO"].ToString() != "")
                {
                    dr["DT_ADMISSAO"] = Convert.ToDateTime(dr["DT_ADMISSAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["PESSOA"] != null && !string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O Pessoa deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }                

                if (dr["REGIME_TRABALHO"] != null && !string.IsNullOrEmpty(dr["REGIME_TRABALHO"].ToString()))
                {
                    if (dr["REGIME_TRABALHO"].ToString().Length > 50)
                    {
                        return "O Regime_trabalho deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["DT_DEMISSAO"] != null && dr["DT_DEMISSAO"].ToString() != "")
                {
                    dr["DT_DEMISSAO"] = Convert.ToDateTime(dr["DT_DEMISSAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["STAMP_ATUALIZACAO"] != null && dr["STAMP_ATUALIZACAO"].ToString() != "")
                {
                    dr["STAMP_ATUALIZACAO"] = Convert.ToDateTime(dr["STAMP_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["MATRICULA"] != null && !string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                {
                    if (dr["MATRICULA"].ToString().Length > 100)
                    {
                        return "A matrícula deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["SENHA_ALTERADA"] != null && !string.IsNullOrEmpty(dr["SENHA_ALTERADA"].ToString()))
                {
                    if (dr["SENHA_ALTERADA"].ToString().Length > 1)
                    {
                        return "O Senha_alterada deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["ANO_INGRESSO"] != null && !string.IsNullOrEmpty(dr["ANO_INGRESSO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ANO_INGRESSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO_INGRESSO"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO_INGRESSO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO_INGRESSO"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ano de ingresso deve ser um valor inteiro com 4 dígitos no máximo.";
                    }
                }

                if (dr["CONCURSO"] != null && !string.IsNullOrEmpty(dr["CONCURSO"].ToString()))
                {
                    if (dr["CONCURSO"].ToString().Length > 20)
                    {
                        return "O concurso deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["CANDIDATO"] != null && !string.IsNullOrEmpty(dr["CANDIDATO"].ToString()))
                {
                    if (dr["CANDIDATO"].ToString().Length > 20)
                    {
                        return "O candidato deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["VOLUNTARIO"] != null && !string.IsNullOrEmpty(dr["VOLUNTARIO"].ToString()))
                {
                    if (dr["VOLUNTARIO"].ToString().Length > 1)
                    {
                        return "A VOLUNTARIO deve possuir no máximo 1 caracteres.";
                    }
                }
                if (dr["USUARIO"] != null && !string.IsNullOrEmpty(dr["USUARIO"].ToString()))
                {
                    if (dr["USUARIO"].ToString().Length > 15)
                    {
                        return "A VOLUNTARIO deve possuir no máximo 15 caracteres.";
                    }
                }
                if (dr["DATACADASTRO"] != null && dr["DATA_CADASTRO"].ToString() != "")
                {
                    dr["DATACADASTRO"] = Convert.ToDateTime(dr["DATACADASTRO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
                if (dr["DATAALTERACAO"] != null && dr["DATAALTERACAO"].ToString() != "")
                {
                    dr["DATAALTERACAO"] = Convert.ToDateTime(dr["DATAALTERACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

