        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["MATRICULA"] == null || string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                {
                    return "Favor informar a matrícula.";
                }

                if (dr["MATRICULA"] != null && !string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                {
                    if (dr["MATRICULA"].ToString().Length > 100)
                    {
                        return "A matrícula deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["FUNCAO_GLP"] == null || string.IsNullOrEmpty(dr["FUNCAO_GLP"].ToString()))
                {
                    return "Favor informar a funçăo GLP.";
                }

                if (dr["FUNCAO_GLP"] != null && !string.IsNullOrEmpty(dr["FUNCAO_GLP"].ToString()))
                {
                    if (dr["FUNCAO_GLP"].ToString().Length > 20)
                    {
                        return "A funçăo GLP deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["ANO"] != null && !string.IsNullOrEmpty(dr["ANO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ano deve ser um valor inteiro com 4 dígitos no máximo.";
                    }
                }

                if (dr["MES"] != null && !string.IsNullOrEmpty(dr["MES"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["MES"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["MES"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["MES"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O męs deve ser um valor inteiro com 2 dígitos no máximo.";
                    }
                }

                if (dr["STATUS"] != null && !string.IsNullOrEmpty(dr["STATUS"].ToString()))
                {
                    if (dr["STATUS"].ToString().Length > 40)
                    {
                        return "O status deve possuir no máximo 40 caracteres.";
                    }
                }

                if (dr["UNIDADE_ENS"] != null && !string.IsNullOrEmpty(dr["UNIDADE_ENS"].ToString()))
                {
                    if (dr["UNIDADE_ENS"].ToString().Length > 20)
                    {
                        return "A unidade de ensino deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DATA"] != null && dr["DATA"].ToString() != "")
                {
                    dr["DATA"] = Convert.ToDateTime(dr["DATA"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["GLP_SOLICITADA"] != null && !string.IsNullOrEmpty(dr["GLP_SOLICITADA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["GLP_SOLICITADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_SOLICITADA"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["GLP_SOLICITADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_SOLICITADA"]).ToString("0.############").Split(',')[1].Length > 2))
                    {
                        return "O número de glp solicitada deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
                    }
                }

                if (dr["GLP_USADA"] != null && !string.IsNullOrEmpty(dr["GLP_USADA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["GLP_USADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_USADA"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["GLP_USADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_USADA"]).ToString("0.############").Split(',')[1].Length > 2))
                    {
                        return "O número de glp usada deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
                    }
                }

                if (dr["GLP_CANCELADA"] != null && !string.IsNullOrEmpty(dr["GLP_CANCELADA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["GLP_CANCELADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_CANCELADA"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["GLP_CANCELADA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["GLP_CANCELADA"]).ToString("0.############").Split(',')[1].Length > 2))
                    {
                        return "O número de glp cancelada deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
                    }
                }

                if (dr["AGRUPAMENTO"] != null && !string.IsNullOrEmpty(dr["AGRUPAMENTO"].ToString()))
                {
                    if (dr["AGRUPAMENTO"].ToString().Length > 50)
                    {
                        return "O grupo de disciplina deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["PRAZO"] != null && !string.IsNullOrEmpty(dr["PRAZO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PRAZO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PRAZO"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["PRAZO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PRAZO"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O prazo deve ser um valor inteiro com 3 dígitos no máximo.";
                    }
                }

                if (dr["CHLIVRE"] != null && !string.IsNullOrEmpty(dr["CHLIVRE"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CHLIVRE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHLIVRE"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["CHLIVRE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHLIVRE"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O Chlivre deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["RESERV01"] != null && !string.IsNullOrEmpty(dr["RESERV01"].ToString()))
                {
                    if (dr["RESERV01"].ToString().Length > 50)
                    {
                        return "O Reserv01 deve possuir no máximo 50 caracteres.";
                    }
                }
                if (dr["USUARIOSOLICITACAOID"] != null && !string.IsNullOrEmpty(dr["USUARIOSOLICITACAOID"].ToString()))
                {
                    if (dr["USUARIOSOLICITACAOID"].ToString().Length > 15)
                    {
                        return "O USUARIOSOLICITACAOID deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["USUARIOANALISEID"] != null && !string.IsNullOrEmpty(dr["USUARIOANALISEID"].ToString()))
                {
                    if (dr["USUARIOANALISEID"].ToString().Length > 15)
                    {
                        return "O Reserv01 deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["DATASOLICITACAO"] != null && dr["DATASOLICITACAO"].ToString() != "")
                {
                    dr["DATASOLICITACAO"] = Convert.ToDateTime(dr["DATASOLICITACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["DATAANALISE"] != null && dr["DATAANALISE"].ToString() != "")
                {
                    dr["DATAANALISE"] = Convert.ToDateTime(dr["DATAANALISE"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["CHLIVREMUNICIPIO"] != null && !string.IsNullOrEmpty(dr["CHLIVREMUNICIPIO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CHLIVREMUNICIPIO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHLIVREMUNICIPIO"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["CHLIVREMUNICIPIO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CHLIVREMUNICIPIO"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ChlivreMunicipio deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["CH_GLPID"] != null && !string.IsNullOrEmpty(dr["CH_GLPID"].ToString()))
                {
                    if (Convert.ToInt32(dr["CH_GLPID"]) > 999999)
                    {
                        return "O chGlpid deve ser um valor inteiro com 6 dígitos no máximo.";
                    }
                }
            }
            return "";
        }

