        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["ID_DOCENTE_FUNCAO_GLP"] == null || string.IsNullOrEmpty(dr["ID_DOCENTE_FUNCAO_GLP"].ToString()))
                {
                    return "Favor informar o id do pedido.";
                }

                if (dr["ID_DOCENTE_FUNCAO_GLP"] != null && !string.IsNullOrEmpty(dr["ID_DOCENTE_FUNCAO_GLP"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ID_DOCENTE_FUNCAO_GLP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_DOCENTE_FUNCAO_GLP"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["ID_DOCENTE_FUNCAO_GLP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ID_DOCENTE_FUNCAO_GLP"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O id do pedido deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["DATA"] == null || string.IsNullOrEmpty(dr["DATA"].ToString()))
                {
                    return "Favor informar o data.";
                }

                if (dr["DATA"] != null && dr["DATA"].ToString() != "")
                {
                    dr["DATA"] = Convert.ToDateTime(dr["DATA"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["STATUS"] == null || string.IsNullOrEmpty(dr["STATUS"].ToString()))
                {
                    return "Favor informar o status.";
                }

                if (dr["STATUS"] != null && !string.IsNullOrEmpty(dr["STATUS"].ToString()))
                {
                    if (dr["STATUS"].ToString().Length > 40)
                    {
                        return "O status deve possuir no máximo 40 caracteres.";
                    }
                }

                if (dr["QTD_GLP"] != null && !string.IsNullOrEmpty(dr["QTD_GLP"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["QTD_GLP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QTD_GLP"]).ToString("0.############").Split(',')[0].Length > 8) || (Convert.ToDecimal(dr["QTD_GLP"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QTD_GLP"]).ToString("0.############").Split(',')[1].Length > 2))
                    {
                        return "A quantidade de glp deve ser um valor numérico com, no máximo, 8 dígitos na parte inteira e 2 casas decimal.";
                    }
                }

                if (dr["USUARIO"] != null && !string.IsNullOrEmpty(dr["USUARIO"].ToString()))
                {
                    if (dr["USUARIO"].ToString().Length > 15)
                    {
                        return "O usuário deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["MOTIVO"] != null && !string.IsNullOrEmpty(dr["MOTIVO"].ToString()))
                {
                    if (dr["MOTIVO"].ToString().Length > 100)
                    {
                        return "O Motivo deve possuir no máximo 100 caracteres.";
                    }
                }
            }
            return "";
        }

