        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_extra_classe.id"
      });
            if (scColumns.Contains("ano")) list.Add("ly_extra_classe.ano");
            if (scColumns.Contains("funcao")) list.Add("ly_extra_classe.funcao");
            if (scColumns.Contains("criterio")) list.Add("ly_extra_classe.criterio");
            if (scColumns.Contains("valor_criterio_inicial")) list.Add("ly_extra_classe.valor_criterio_inicial");
            if (scColumns.Contains("valor_criterio_final")) list.Add("ly_extra_classe.valor_criterio_final");
            if (scColumns.Contains("qtde_funcao_permitida")) list.Add("ly_extra_classe.qtde_funcao_permitida");
            if (scColumns.Contains("descricao03")) list.Add("ly_funcao.descricao descricao03");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_extra_classe " +
                     "INNER JOIN ly_funcao " +
                       "ON ly_funcao.funcao = ly_extra_classe.funcao " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_extra_classe");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_extra_classe");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["ANO"] != null && string.IsNullOrEmpty(dr["ANO"].ToString()))
                    dr["ANO"] = DBNull.Value;
                if (dr["FUNCAO"] != null && string.IsNullOrEmpty(dr["FUNCAO"].ToString()))
                    dr["FUNCAO"] = DBNull.Value;
                if (dr["CRITERIO"] != null && string.IsNullOrEmpty(dr["CRITERIO"].ToString()))
                    dr["CRITERIO"] = DBNull.Value;
                if (dr["VALOR_CRITERIO_INICIAL"] != null && string.IsNullOrEmpty(dr["VALOR_CRITERIO_INICIAL"].ToString()))
                    dr["VALOR_CRITERIO_INICIAL"] = DBNull.Value;
                if (dr["VALOR_CRITERIO_FINAL"] != null && string.IsNullOrEmpty(dr["VALOR_CRITERIO_FINAL"].ToString()))
                    dr["VALOR_CRITERIO_FINAL"] = DBNull.Value;
                if (dr["QTDE_FUNCAO_PERMITIDA"] != null && string.IsNullOrEmpty(dr["QTDE_FUNCAO_PERMITIDA"].ToString()))
                    dr["QTDE_FUNCAO_PERMITIDA"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["ANO"] == null || string.IsNullOrEmpty(dr["ANO"].ToString()))
                {
                    return "Favor informar o Ano.";
                }

                if (dr["ANO"] != null && !string.IsNullOrEmpty(dr["ANO"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ANO"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O Ano deve ser um valor inteiro com 4 dígitos no máximo.";
                    }
                }

                if (dr["FUNCAO"] == null || string.IsNullOrEmpty(dr["FUNCAO"].ToString()))
                {
                    return "Favor informar o Funcao.";
                }

                if (dr["FUNCAO"] != null && !string.IsNullOrEmpty(dr["FUNCAO"].ToString()))
                {
                    if (dr["FUNCAO"].ToString().Length > 20)
                    {
                        return "O Funcao deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["CRITERIO"] == null || string.IsNullOrEmpty(dr["CRITERIO"].ToString()))
                {
                    return "Favor informar o Criterio.";
                }

                if (dr["CRITERIO"] != null && !string.IsNullOrEmpty(dr["CRITERIO"].ToString()))
                {
                    if (dr["CRITERIO"].ToString().Length > 50)
                    {
                        return "O Criterio deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["VALOR_CRITERIO_INICIAL"] == null || string.IsNullOrEmpty(dr["VALOR_CRITERIO_INICIAL"].ToString()))
                {
                    return "Favor informar o Valor_criterio_inicial.";
                }

                if (dr["VALOR_CRITERIO_INICIAL"] != null && !string.IsNullOrEmpty(dr["VALOR_CRITERIO_INICIAL"].ToString()))
                {
                    if (dr["VALOR_CRITERIO_INICIAL"].ToString().Length > 20)
                    {
                        return "O Valor_criterio_inicial deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["VALOR_CRITERIO_FINAL"] == null || string.IsNullOrEmpty(dr["VALOR_CRITERIO_FINAL"].ToString()))
                {
                    return "Favor informar o Valor_criterio_final.";
                }

                if (dr["VALOR_CRITERIO_FINAL"] != null && !string.IsNullOrEmpty(dr["VALOR_CRITERIO_FINAL"].ToString()))
                {
                    if (dr["VALOR_CRITERIO_FINAL"].ToString().Length > 20)
                    {
                        return "O Valor_criterio_final deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["QTDE_FUNCAO_PERMITIDA"] == null || string.IsNullOrEmpty(dr["QTDE_FUNCAO_PERMITIDA"].ToString()))
                {
                    return "Favor informar o Qtde_funcao_permitida.";
                }

                if (dr["QTDE_FUNCAO_PERMITIDA"] != null && !string.IsNullOrEmpty(dr["QTDE_FUNCAO_PERMITIDA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["QTDE_FUNCAO_PERMITIDA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QTDE_FUNCAO_PERMITIDA"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["QTDE_FUNCAO_PERMITIDA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["QTDE_FUNCAO_PERMITIDA"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O Qtde_funcao_permitida deve ser um valor inteiro com 4 dígitos no máximo.";
                    }
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

