        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "funcao") { result.Add(toLower ? "funcao" : column); continue; }
                    if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                    if (lower == "funcaobb") { result.Add(toLower ? "funcaobb" : column); continue; }
                    if (lower == "tipo") { result.Add(toLower ? "tipo" : column); continue; }
                    if (lower == "campo_01") { result.Add(toLower ? "campo_01" : column); continue; }
                    if (lower == "campo_02") { result.Add(toLower ? "campo_02" : column); continue; }
                    if (lower == "campo_03") { result.Add(toLower ? "campo_03" : column); continue; }
                    if (lower == "campo_04") { result.Add(toLower ? "campo_04" : column); continue; }
                    if (lower == "campo_05") { result.Add(toLower ? "campo_05" : column); continue; }
                    if (lower == "campo_06") { result.Add(toLower ? "campo_06" : column); continue; }
                    if (lower == "campo_07") { result.Add(toLower ? "campo_07" : column); continue; }
                    if (lower == "campo_08") { result.Add(toLower ? "campo_08" : column); continue; }
                    if (lower == "campo_09") { result.Add(toLower ? "campo_09" : column); continue; }
                    if (lower == "campo_10") { result.Add(toLower ? "campo_10" : column); continue; }
                    if (lower == "semcargahorariaefetiva") { result.Add(toLower ? "semcargahorariaefetiva" : column); continue; }
                    if (lower == "ATIVO") { result.Add(toLower ? "ATIVO" : column); continue; }
                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "funcao", "descricao", "funcaobb", "tipo", "campo_01", "campo_02", 
                                           "campo_03", "campo_04", "campo_05", "campo_06", "campo_07", "campo_08", "campo_09", 
                                           "campo_10","semcargahorariaefetiva","ATIVO" }
                                    : new string[] { "FUNCAO", "DESCRICAO", "FUNCAOBB", "TIPO", "CAMPO_01", "CAMPO_02", 
                                           "CAMPO_03", "CAMPO_04", "CAMPO_05", "CAMPO_06", "CAMPO_07", "CAMPO_08", "CAMPO_09", 
                                           "CAMPO_10","SEMCARGAHORARIAEFETIVA","ATIVO"  });
                else
                    result.AddRange(toLower
                                    ? new string[] { "funcao", "descricao", "funcaobb", "tipo", "campo_01", "campo_02", 
                                           "campo_03", "campo_04", "campo_05", "campo_06", "campo_07", "campo_08", "campo_09", 
                                           "campo_10","semcargahorariaefetiva","ATIVO"  }
                                    : new string[] { "FUNCAO", "DESCRICAO", "FUNCAOBB", "TIPO", "CAMPO_01", "CAMPO_02", 
                                           "CAMPO_03", "CAMPO_04", "CAMPO_05", "CAMPO_06", "CAMPO_07", "CAMPO_08", "CAMPO_09", 
                                           "CAMPO_10","semcargahorariaefetiva","ATIVO"  });

            return result;
        }


