            cm.Parameters.Add(new TParameter("datacadastro", OleDbType.Date, 0, ParameterDirection.InputOutput, true, 0, 0, "DATACADASTRO", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(DateTime.ParseExact("01/01/1753", "dd/MM/yyyy", CultureInfo.InvariantCulture))));
            cm.Parameters.Add(new TParameter("dataalteracao", OleDbType.Date, 0, ParameterDirection.InputOutput, true, 0, 0, "DATAALTERACAO", DataRowVersion.Current, operation == CommandOperation.Insert ? DBNull.Value : (DbObject)(DateTime.ParseExact("01/01/1753", "dd/MM/yyyy", CultureInfo.InvariantCulture))));


            switch (operation)
            {
                case CommandOperation.Insert: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Insert")); break;
                case CommandOperation.Update: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Update")); break;
                case CommandOperation.Delete: cm.Parameters.Add(new TParameter("tipoComando", OleDbType.VarChar, 10, ParameterDirection.Input, true, 0, 0, string.Empty, DataRowVersion.Current, "Delete")); break;
            }
            cm.Parameters.Add(new TParameter("erro", OleDbType.VarChar, 1024, ParameterDirection.Output, true, 0, 0, string.Empty, DataRowVersion.Default, DBNull.Value));

            return cm;
        }

        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "agrupamento") { result.Add(toLower ? "agrupamento" : column); continue; }
                    if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                    if (lower == "stamp_atualizacao") { result.Add(toLower ? "stamp_atualizacao" : column); continue; }
                    if (lower == "tipo") { result.Add(toLower ? "tipo" : column); continue; }
                    if (lower == "disp_glp_dol") { result.Add(toLower ? "disp_glp_dol" : column); continue; }
                    if (lower == "ingresso") { result.Add(toLower ? "ingresso" : column); continue; }
                    if (lower == "ativo") { result.Add(toLower ? "ativo" : column); continue; }
                    if (lower == "usuario") { result.Add(toLower ? "usuario" : column); continue; }
                    if (lower == "datacadastro") { result.Add(toLower ? "datacadastro" : column); continue; }
                    if (lower == "dataalteracao") { result.Add(toLower ? "dataalteracao" : column); continue; }
                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "agrupamento", "descricao", "stamp_atualizacao", "tipo", "disp_glp_dol", "ingresso","ativo" ,"usuario","datacadastro","dataalteracao" }
                                    : new string[] { "AGRUPAMENTO", "DESCRICAO", "STAMP_ATUALIZACAO", "TIPO", "DISP_GLP_DOL", "INGRESSO","ATIVO" ,"USUARIO","DATACADASTRO","DATAALTERACAO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "agrupamento", "descricao", "stamp_atualizacao", "tipo", "disp_glp_dol", "ingresso", "ativo", "usuario", "datacadastro", "dataalteracao" }
                                    : new string[] { "AGRUPAMENTO", "DESCRICAO", "STAMP_ATUALIZACAO", "TIPO", "DISP_GLP_DOL", "INGRESSO", "ATIVO", "USUARIO", "DATACADASTRO", "DATAALTERACAO" });

            return result;
        }


