        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_grupo_habilitacao_disc.agrupamento", "ly_grupo_habilitacao_disc.disciplina"
      });
            if (scColumns.Contains("stamp_atualizacao")) list.Add("ly_grupo_habilitacao_disc.stamp_atualizacao");
            if (scColumns.Contains("nome02")) list.Add("ly_disciplina.nome nome02");
            if (scColumns.Contains("nome_compl03")) list.Add("ly_disciplina.nome_compl nome_compl03");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_grupo_habilitacao_disc " +
                     "INNER JOIN ly_disciplina " +
                       "ON ly_disciplina.disciplina = ly_grupo_habilitacao_disc.disciplina " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

