            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "num_func") { result.Add(toLower ? "num_func" : column); continue; }
                    if (lower == "agrupamento") { result.Add(toLower ? "agrupamento" : column); continue; }
                    if (lower == "provisorio") { result.Add(toLower ? "provisorio" : column); continue; }
                    if (lower == "dt_limite") { result.Add(toLower ? "dt_limite" : column); continue; }
                    if (lower == "agrupamento_ingresso") { result.Add(toLower ? "agrupamento_ingresso" : column); continue; }
                    if (lower == "stamp_atualizacao") { result.Add(toLower ? "stamp_atualizacao" : column); continue; }
                    if (lower == "campo_01") { result.Add(toLower ? "campo_01" : column); continue; }
                    if (lower == "campo_02") { result.Add(toLower ? "campo_02" : column); continue; }
                    if (!tabPrincipal)
                    {
                        if (lower == "nome_compl") { result.Add(toLower ? "nome_compl" : column); continue; }
                        if (lower == "matricula") { result.Add(toLower ? "matricula" : column); continue; }
                        if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "num_func", "agrupamento", "provisorio", "dt_limite", "agrupamento_ingresso", 
                                           "stamp_atualizacao", "campo_01", "campo_02" }
                                    : new string[] { "NUM_FUNC", "AGRUPAMENTO", "PROVISORIO", "DT_LIMITE", "AGRUPAMENTO_INGRESSO", 
                                           "STAMP_ATUALIZACAO", "CAMPO_01", "CAMPO_02" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "num_func", "agrupamento", "provisorio", "dt_limite", "agrupamento_ingresso", 
                                           "stamp_atualizacao", "campo_01", "campo_02", "nome_compl", "matricula", "descricao" }
                                    : new string[] { "NUM_FUNC", "AGRUPAMENTO", "PROVISORIO", "DT_LIMITE", "AGRUPAMENTO_INGRESSO", 
                                           "STAMP_ATUALIZACAO", "CAMPO_01", "CAMPO_02", "NOME_COMPL", "MATRICULA", "DESCRICAO" });

            return result;
        }


