        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_grupo_habilitacao_doc.num_func", "ly_grupo_habilitacao_doc.agrupamento","ly_grupo_habilitacao_doc.provisorio"
      });
            if (scColumns.Contains("dt_limite")) list.Add("ly_grupo_habilitacao_doc.dt_limite");
            if (scColumns.Contains("agrupamento_ingresso")) list.Add("ly_grupo_habilitacao_doc.agrupamento_ingresso");
            if (scColumns.Contains("stamp_atualizacao")) list.Add("ly_grupo_habilitacao_doc.stamp_atualizacao");
            if (scColumns.Contains("campo_01")) list.Add("ly_grupo_habilitacao_doc.campo_01");
            if (scColumns.Contains("campo_02")) list.Add("ly_grupo_habilitacao_doc.campo_02");
            if (scColumns.Contains("nome_compl")) list.Add("ly_pessoa.nome_compl");
            if (scColumns.Contains("matricula")) list.Add("ly_docente.matricula");
            if (scColumns.Contains("descricao")) list.Add("ly_grupo_habilitacao.descricao");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_grupo_habilitacao_doc " +
                     "INNER JOIN ly_grupo_habilitacao " +
                       "ON ly_grupo_habilitacao.agrupamento = ly_grupo_habilitacao_doc.agrupamento " +
                     "INNER JOIN ly_docente " +
                       "ON ly_docente.num_func = ly_grupo_habilitacao_doc.num_func " +
                        "INNER JOIN ly_pessoa " +
                       "ON ly_pessoa.pessoa = ly_docente.pessoa " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_grupo_habilitacao_doc");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_grupo_habilitacao_doc");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["NUM_FUNC"] != null && string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                    dr["NUM_FUNC"] = DBNull.Value;
                if (dr["AGRUPAMENTO"] != null && string.IsNullOrEmpty(dr["AGRUPAMENTO"].ToString()))
                    dr["AGRUPAMENTO"] = DBNull.Value;
                if (dr["PROVISORIO"] != null && string.IsNullOrEmpty(dr["PROVISORIO"].ToString()))
                    dr["PROVISORIO"] = DBNull.Value;
                if (dr["AGRUPAMENTO_INGRESSO"] != null && string.IsNullOrEmpty(dr["AGRUPAMENTO_INGRESSO"].ToString()))
                    dr["AGRUPAMENTO_INGRESSO"] = DBNull.Value;
                if (dr["CAMPO_01"] != null && string.IsNullOrEmpty(dr["CAMPO_01"].ToString()))
                    dr["CAMPO_01"] = DBNull.Value;
                if (dr["CAMPO_02"] != null && string.IsNullOrEmpty(dr["CAMPO_02"].ToString()))
                    dr["CAMPO_02"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["NUM_FUNC"] == null || string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                {
                    return "Favor informar o número do funcionário.";
                }

                if (dr["NUM_FUNC"] != null && !string.IsNullOrEmpty(dr["NUM_FUNC"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',')[0].Length > 15) || (Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["NUM_FUNC"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O número do funcionário deve ser um valor inteiro com 15 dígitos no máximo.";
                    }
                }

                if (dr["AGRUPAMENTO"] == null || string.IsNullOrEmpty(dr["AGRUPAMENTO"].ToString()))
                {
                    return "Favor informar o grupo.";
                }

                if (dr["AGRUPAMENTO"] != null && !string.IsNullOrEmpty(dr["AGRUPAMENTO"].ToString()))
                {
                    if (dr["AGRUPAMENTO"].ToString().Length > 50)
                    {
                        return "O grupo deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["PROVISORIO"] == null || string.IsNullOrEmpty(dr["PROVISORIO"].ToString()))
                {
                    return "Favor informar o provisório.";
                }

                if (dr["PROVISORIO"] != null && !string.IsNullOrEmpty(dr["PROVISORIO"].ToString()))
                {
                    if (dr["PROVISORIO"].ToString().Length > 1)
                    {
                        return "O provisório deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["DT_LIMITE"] != null && dr["DT_LIMITE"].ToString() != "")
                {
                    dr["DT_LIMITE"] = Convert.ToDateTime(dr["DT_LIMITE"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["AGRUPAMENTO_INGRESSO"] != null && !string.IsNullOrEmpty(dr["AGRUPAMENTO_INGRESSO"].ToString()))
                {
                    if (dr["AGRUPAMENTO_INGRESSO"].ToString().Length > 1)
                    {
                        return "O grupo de ingresso deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["STAMP_ATUALIZACAO"] != null && dr["STAMP_ATUALIZACAO"].ToString() != "")
                {
                    dr["STAMP_ATUALIZACAO"] = Convert.ToDateTime(dr["STAMP_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["CAMPO_01"] != null && !string.IsNullOrEmpty(dr["CAMPO_01"].ToString()))
                {
                    if (dr["CAMPO_01"].ToString().Length > 20)
                    {
                        return "O Campo_01 deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["CAMPO_02"] != null && !string.IsNullOrEmpty(dr["CAMPO_02"].ToString()))
                {
                    if (dr["CAMPO_02"].ToString().Length > 20)
                    {
                        return "O Campo_02 deve possuir no máximo 20 caracteres.";
                    }
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

