                    if (lower == "tipo_inst") { result.Add(toLower ? "tipo_inst" : column); continue; }
                    if (lower == "pais") { result.Add(toLower ? "pais" : column); continue; }
                    if (lower == "tipo_origem") { result.Add(toLower ? "tipo_origem" : column); continue; }
                    if (lower == "web_site") { result.Add(toLower ? "web_site" : column); continue; }
                    if (lower == "e_mail") { result.Add(toLower ? "e_mail" : column); continue; }
                    if (lower == "nucleo_regional") { result.Add(toLower ? "nucleo_regional" : column); continue; }
                    if (lower == "ato_reconhecimento") { result.Add(toLower ? "ato_reconhecimento" : column); continue; }
                    if (lower == "mantenedora") { result.Add(toLower ? "mantenedora" : column); continue; }
                    if (lower == "ato_funcionamento") { result.Add(toLower ? "ato_funcionamento" : column); continue; }
                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "outra_faculdade", "nome_comp", "nome_abrev", "endereco", "end_num", 
                                           "end_compl", "bairro", "municipio", "cep", "caixa_postal", "fone", "fax", "cgc", 
                                           "local_vest", "tipo_inst", "pais", "tipo_origem", "web_site", "e_mail", "nucleo_regional", 
                                           "ato_reconhecimento", "mantenedora", "ato_funcionamento" }
                                    : new string[] { "OUTRA_FACULDADE", "NOME_COMP", "NOME_ABREV", "ENDERECO", "END_NUM", 
                                           "END_COMPL", "BAIRRO", "MUNICIPIO", "CEP", "CAIXA_POSTAL", "FONE", "FAX", "CGC", 
                                           "LOCAL_VEST", "TIPO_INST", "PAIS", "TIPO_ORIGEM", "WEB_SITE", "E_MAIL", "NUCLEO_REGIONAL", 
                                           "ATO_RECONHECIMENTO", "MANTENEDORA", "ATO_FUNCIONAMENTO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "outra_faculdade", "nome_comp", "nome_abrev", "endereco", "end_num", 
                                           "end_compl", "bairro", "municipio", "cep", "caixa_postal", "fone", "fax", "cgc", 
                                           "local_vest", "tipo_inst", "pais", "tipo_origem", "web_site", "e_mail", "nucleo_regional", 
                                           "ato_reconhecimento", "mantenedora", "ato_funcionamento" }
                                    : new string[] { "OUTRA_FACULDADE", "NOME_COMP", "NOME_ABREV", "ENDERECO", "END_NUM", 
