        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_instituicao.outra_faculdade"
      });
            if (scColumns.Contains("nome_comp")) list.Add("ly_instituicao.nome_comp");
            if (scColumns.Contains("nome_abrev")) list.Add("ly_instituicao.nome_abrev");
            if (scColumns.Contains("endereco")) list.Add("ly_instituicao.endereco");
            if (scColumns.Contains("end_num")) list.Add("ly_instituicao.end_num");
            if (scColumns.Contains("end_compl")) list.Add("ly_instituicao.end_compl");
            if (scColumns.Contains("bairro")) list.Add("ly_instituicao.bairro");
            if (scColumns.Contains("municipio")) list.Add("ly_instituicao.municipio");
            if (scColumns.Contains("cep")) list.Add("ly_instituicao.cep");
            if (scColumns.Contains("caixa_postal")) list.Add("ly_instituicao.caixa_postal");
            if (scColumns.Contains("fone")) list.Add("ly_instituicao.fone");
            if (scColumns.Contains("fax")) list.Add("ly_instituicao.fax");
            if (scColumns.Contains("cgc")) list.Add("ly_instituicao.cgc");
            if (scColumns.Contains("local_vest")) list.Add("ly_instituicao.local_vest");
            if (scColumns.Contains("tipo_inst")) list.Add("ly_instituicao.tipo_inst");
            if (scColumns.Contains("pais")) list.Add("ly_instituicao.pais");
            if (scColumns.Contains("tipo_origem")) list.Add("ly_instituicao.tipo_origem");
            if (scColumns.Contains("web_site")) list.Add("ly_instituicao.web_site");
            if (scColumns.Contains("e_mail")) list.Add("ly_instituicao.e_mail");
            if (scColumns.Contains("nucleo_regional")) list.Add("ly_instituicao.nucleo_regional");
            if (scColumns.Contains("ato_reconhecimento")) list.Add("ly_instituicao.ato_reconhecimento");
            if (scColumns.Contains("mantenedora")) list.Add("ly_instituicao.mantenedora");
            if (scColumns.Contains("ato_funcionamento")) list.Add("ly_instituicao.ato_funcionamento");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_instituicao " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_instituicao");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_instituicao");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

