                if (dr["ATO_FUNCIONAMENTO"] != null && !string.IsNullOrEmpty(dr["ATO_FUNCIONAMENTO"].ToString()))
                {
                    if (dr["ATO_FUNCIONAMENTO"].ToString().Length > 50)
                    {
                        return "O Ato_funcionamento deve possuir no máximo 50 caracteres.";
                    }
                }
            }
            return "";
        }

