                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "num_func", "dtini", "dtfim", "motivo", "dt_retorno", "stamp_atualizacao" }
                                    : new string[] { "NUM_FUNC", "DTINI", "DTFIM", "MOTIVO", "DT_RETORNO", "STAMP_ATUALIZACAO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "num_func", "dtini", "dtfim", "motivo", "dt_retorno", "stamp_atualizacao" }
                                    : new string[] { "NUM_FUNC", "DTINI", "DTFIM", "MOTIVO", "DT_RETORNO", "STAMP_ATUALIZACAO" });

