        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "motivo") { result.Add(toLower ? "motivo" : column); continue; }
                    if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                    if (lower == "possui_dtfim") { result.Add(toLower ? "possui_dtfim" : column); continue; }
                    if (lower == "periodo_limite") { result.Add(toLower ? "periodo_limite" : column); continue; }
                    if (lower == "bloqueia_glp") { result.Add(toLower ? "bloqueia_glp" : column); continue; }
                    if (lower == "participacontratotemporario") { result.Add(toLower ? "participacontratotemporario" : column); continue; }
                    if (lower == "validaalocacao") { result.Add(toLower ? "validaalocacao" : column); continue; }
                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "motivo", "descricao", "possui_dtfim", "periodo_limite", "bloqueia_glp", "participacontratotemporario", "validaalocacao" }
                                    : new string[] { "MOTIVO", "DESCRICAO", "POSSUI_DTFIM", "PERIODO_LIMITE", "BLOQUEIA_GLP", "PARTICIPACONTRATOTEMPORARIO", "VALIDAALOCACAO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "motivo", "descricao", "possui_dtfim", "periodo_limite", "bloqueia_glp", "participacontratotemporario", "validaalocacao" }
                                    : new string[] { "MOTIVO", "DESCRICAO", "POSSUI_DTFIM", "PERIODO_LIMITE", "BLOQUEIA_GLP", "PARTICIPACONTRATOTEMPORARIO", "VALIDAALOCACAO" });

            return result;
        }


