        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_licencas.motivo"
      });
            if (scColumns.Contains("descricao")) list.Add("ly_licencas.descricao");
            if (scColumns.Contains("possui_dtfim")) list.Add("ly_licencas.possui_dtfim");
            if (scColumns.Contains("periodo_limite")) list.Add("ly_licencas.periodo_limite");
            if (scColumns.Contains("bloqueia_glp")) list.Add("ly_licencas.bloqueia_glp");
            if (scColumns.Contains("participacontratotemporario")) list.Add("ly_licencas.participacontratotemporario");
            if (scColumns.Contains("validaalocacao")) list.Add("ly_licencas.validaalocacao");

            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_licencas " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_licencas");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_licencas");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["MOTIVO"] != null && string.IsNullOrEmpty(dr["MOTIVO"].ToString()))
                    dr["MOTIVO"] = DBNull.Value;
                if (dr["DESCRICAO"] != null && string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                    dr["DESCRICAO"] = DBNull.Value;
                if (dr["POSSUI_DTFIM"] != null && string.IsNullOrEmpty(dr["POSSUI_DTFIM"].ToString()))
                    dr["POSSUI_DTFIM"] = DBNull.Value;
                if (dr["PERIODO_LIMITE"] != null && string.IsNullOrEmpty(dr["PERIODO_LIMITE"].ToString()))
                    dr["PERIODO_LIMITE"] = DBNull.Value;
                if (dr["BLOQUEIA_GLP"] != null && string.IsNullOrEmpty(dr["BLOQUEIA_GLP"].ToString()))
                    dr["BLOQUEIA_GLP"] = DBNull.Value;
                if (dr["PARTICIPACONTRATOTEMPORARIO"] != null && string.IsNullOrEmpty(dr["PARTICIPACONTRATOTEMPORARIO"].ToString()))
                    dr["PARTICIPACONTRATOTEMPORARIO"] = DBNull.Value;
                if (dr["VALIDAALOCACAO"] != null && string.IsNullOrEmpty(dr["VALIDAALOCACAO"].ToString()))
                    dr["VALIDAALOCACAO"] = DBNull.Value;

            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["MOTIVO"] == null || string.IsNullOrEmpty(dr["MOTIVO"].ToString()))
                {
                    return "Favor informar a licença.";
                }

                if (dr["MOTIVO"] != null && !string.IsNullOrEmpty(dr["MOTIVO"].ToString()))
                {
                    if (dr["MOTIVO"].ToString().Length > 100)
                    {
                        return "A licença deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["DESCRICAO"] == null || string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    return "Favor informar a licença.";
                }

                if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    if (dr["DESCRICAO"].ToString().Length > 100)
                    {
                        return "A licença deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["POSSUI_DTFIM"] != null && !string.IsNullOrEmpty(dr["POSSUI_DTFIM"].ToString()))
                {
                    if (dr["POSSUI_DTFIM"].ToString().Length > 1)
                    {
                        return "O possui data final deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["PERIODO_LIMITE"] != null && !string.IsNullOrEmpty(dr["PERIODO_LIMITE"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PERIODO_LIMITE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODO_LIMITE"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PERIODO_LIMITE"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PERIODO_LIMITE"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O período limite da licença deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["BLOQUEIA_GLP"] != null && !string.IsNullOrEmpty(dr["BLOQUEIA_GLP"].ToString()))
                {
                    if (dr["BLOQUEIA_GLP"].ToString().Length > 1)
                    {
                        return "O bloqueio de glp deve possuir no máximo 1 caractere.";
                    }
                }
                if (dr["PARTICIPACONTRATOTEMPORARIO"] != null && !string.IsNullOrEmpty(dr["PARTICIPACONTRATOTEMPORARIO"].ToString()))
                {
                    if (dr["PARTICIPACONTRATOTEMPORARIO"].ToString().Length > 1)
                    {
                        return "O Participa do Contrato Temporário deve possuir no máximo 1 caractere.";
                    }
                }
                if (dr["VALIDAALOCACAO"] != null && !string.IsNullOrEmpty(dr["VALIDAALOCACAO"].ToString()))
                {
                    if (dr["VALIDAALOCACAO"].ToString().Length > 1)
                    {
                        return "O Valida Alocaçăo deve possuir no máximo 1 caractere.";
                    }
                }

            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

