        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "pessoa") { result.Add(toLower ? "pessoa" : column); continue; }
                    if (lower == "matricula") { result.Add(toLower ? "matricula" : column); continue; }
                    if (lower == "ordem") { result.Add(toLower ? "ordem" : column); continue; }
                    if (lower == "funcao") { result.Add(toLower ? "funcao" : column); continue; }
                    if (lower == "turno") { result.Add(toLower ? "turno" : column); continue; }
                    if (lower == "data_desativacao") { result.Add(toLower ? "data_desativacao" : column); continue; }
                    if (lower == "ato_oficial") { result.Add(toLower ? "ato_oficial" : column); continue; }
                    if (lower == "resp_documentacao") { result.Add(toLower ? "resp_documentacao" : column); continue; }
                    if (lower == "unidade_fis") { result.Add(toLower ? "unidade_fis" : column); continue; }
                    if (lower == "data_nomeacao") { result.Add(toLower ? "data_nomeacao" : column); continue; }
                    if (lower == "data_nomeacao_do") { result.Add(toLower ? "data_nomeacao_do" : column); continue; }
                    if (lower == "data_desativacao_do") { result.Add(toLower ? "data_desativacao_do" : column); continue; }
                    if (lower == "tipo_desativacao") { result.Add(toLower ? "tipo_desativacao" : column); continue; }
                    if (lower == "unidade_ens") { result.Add(toLower ? "unidade_ens" : column); continue; }
                    if (lower == "nucleo") { result.Add(toLower ? "nucleo" : column); continue; }
                    if (lower == "setor") { result.Add(toLower ? "setor" : column); continue; }
                    if (lower == "readaptado") { result.Add(toLower ? "readaptado" : column); continue; }
                    if (lower == "categoria") { result.Add(toLower ? "categoria" : column); continue; }
                    if (lower == "dt_inicio_readaptacao") { result.Add(toLower ? "dt_inicio_readaptacao" : column); continue; }
                    if (lower == "dt_fim_readaptacao") { result.Add(toLower ? "dt_fim_readaptacao" : column); continue; }
                    if (lower == "motivo_readaptacao") { result.Add(toLower ? "motivo_readaptacao" : column); continue; }
                    if (lower == "usuario") { result.Add(toLower ? "usuario" : column); continue; }
                    if (lower == "data_atualizacao") { result.Add(toLower ? "data_atualizacao" : column); continue; }
                    if (!tabPrincipal)
                    {
                        if (lower == "nome_compl") { result.Add(toLower ? "nome_compl" : column); continue; }
                        if (lower == "nucleo02") { result.Add(toLower ? "nucleo02" : column); continue; }
                        if (lower == "municipio") { result.Add(toLower ? "municipio" : column); continue; }
                        if (lower == "nome_comp02") { result.Add(toLower ? "nome_comp02" : column); continue; }
                        if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                        if (lower == "descricao02") { result.Add(toLower ? "descricao02" : column); continue; }
                        if (lower == "descricao03") { result.Add(toLower ? "descricao03" : column); continue; }
                        if (lower == "campo_01") { result.Add(toLower ? "campo_01" : column); continue; }
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "matricula", "ordem", "funcao", "turno", 
                                           "data_desativacao", "ato_oficial", "resp_documentacao", "unidade_fis", "data_nomeacao", 
                                           "data_nomeacao_do", "data_desativacao_do", "tipo_desativacao", "unidade_ens", "nucleo", 
                                           "setor", "readaptado", "categoria", "dt_inicio_readaptacao", "dt_fim_readaptacao", "motivo_readaptacao", 
                                           "usuario", "data_atualizacao" }
                                    : new string[] { "PESSOA", "MATRICULA", "ORDEM", "FUNCAO", "TURNO", 
                                           "DATA_DESATIVACAO", "ATO_OFICIAL", "RESP_DOCUMENTACAO", "UNIDADE_FIS", "DATA_NOMEACAO", 
                                           "DATA_NOMEACAO_DO", "DATA_DESATIVACAO_DO", "TIPO_DESATIVACAO", "UNIDADE_ENS", "NUCLEO", 
                                           "SETOR", "READAPTADO", "CATEGORIA", "DT_INICIO_READAPTACAO", "DT_FIM_READAPTACAO", "MOTIVO_READAPTACAO", 
                                           "USUARIO", "DATA_ATUALIZACAO" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "matricula", "ordem", "funcao", "turno", 
                                           "data_desativacao", "ato_oficial", "resp_documentacao", "unidade_fis", "data_nomeacao", 
                                           "data_nomeacao_do", "data_desativacao_do", "tipo_desativacao", "unidade_ens", "nucleo", 
                                           "setor", "readaptado", "categoria", "dt_inicio_readaptacao", "dt_fim_readaptacao", "motivo_readaptacao", 
                                           "usuario", "data_atualizacao", "nome_compl", "nucleo02", "municipio", "nome_comp02", 
                                           "descricao", "descricao02", "descricao03", "campo_01" }
                                    : new string[] { "PESSOA", "MATRICULA", "ORDEM", "FUNCAO", "TURNO", 
                                           "DATA_DESATIVACAO", "ATO_OFICIAL","RESP_DOCUMENTACAO", "UNIDADE_FIS", "DATA_NOMEACAO", 
                                           "DATA_NOMEACAO_DO", "DATA_DESATIVACAO_DO", "TIPO_DESATIVACAO", "UNIDADE_ENS", "NUCLEO", 
                                           "SETOR", "READAPTADO", "CATEGORIA", "DT_INICIO_READAPTACAO", "DT_FIM_READAPTACAO", "MOTIVO_READAPTACAO", 
                                           "USUARIO", "DATA_ATUALIZACAO", "NOME_COMPL", "NUCLEO02", "MUNICIPIO", "NOME_COMP02", 
                                           "DESCRICAO", "DESCRICAO02", "DESCRICAO03", "CAMPO_01" });

            return result;
        }


