        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_lotacao.pessoa", "ly_lotacao.matricula", "ly_lotacao.ordem"
      });
            if (scColumns.Contains("funcao")) list.Add("ly_lotacao.funcao");
            if (scColumns.Contains("turno")) list.Add("ly_lotacao.turno");
            if (scColumns.Contains("data_desativacao")) list.Add("ly_lotacao.data_desativacao");
            if (scColumns.Contains("ato_oficial")) list.Add("ly_lotacao.ato_oficial");
            if (scColumns.Contains("resp_documentacao")) list.Add("ly_lotacao.resp_documentacao");
            if (scColumns.Contains("unidade_fis")) list.Add("ly_lotacao.unidade_fis");
            if (scColumns.Contains("data_nomeacao")) list.Add("ly_lotacao.data_nomeacao");
            if (scColumns.Contains("data_nomeacao_do")) list.Add("ly_lotacao.data_nomeacao_do");
            if (scColumns.Contains("data_desativacao_do")) list.Add("ly_lotacao.data_desativacao_do");
            if (scColumns.Contains("tipo_desativacao")) list.Add("ly_lotacao.tipo_desativacao");
            if (scColumns.Contains("unidade_ens")) list.Add("ly_lotacao.unidade_ens");
            if (scColumns.Contains("nucleo")) list.Add("ly_lotacao.nucleo");
            if (scColumns.Contains("setor")) list.Add("ly_lotacao.setor");
            if (scColumns.Contains("readaptado")) list.Add("ly_lotacao.readaptado");
            if (scColumns.Contains("categoria")) list.Add("ly_lotacao.categoria");
            if (scColumns.Contains("dt_inicio_readaptacao")) list.Add("ly_lotacao.dt_inicio_readaptacao");
            if (scColumns.Contains("dt_fim_readaptacao")) list.Add("ly_lotacao.dt_fim_readaptacao");
            if (scColumns.Contains("motivo_readaptacao")) list.Add("ly_lotacao.motivo_readaptacao");
            if (scColumns.Contains("usuario")) list.Add("ly_lotacao.usuario");
            if (scColumns.Contains("data_atualizacao")) list.Add("ly_lotacao.data_atualizacao");
            if (scColumns.Contains("nome_compl")) list.Add("ly_pessoa.nome_compl");
            if (scColumns.Contains("nucleo02")) list.Add("ly_unidade_ensino.nucleo nucleo02");
            if (scColumns.Contains("municipio")) list.Add("ly_unidade_ensino.municipio");
            if (scColumns.Contains("nome_comp02")) list.Add("ly_unidade_ensino.nome_comp nome_comp02");
            if (scColumns.Contains("descricao")) list.Add("ly_turno.descricao");
            if (scColumns.Contains("descricao02")) list.Add("ly_funcao.descricao descricao02");
            if (scColumns.Contains("descricao03")) list.Add("ly_nucleo.descricao descricao03");
            if (scColumns.Contains("campo_01")) list.Add("ly_funcao.campo_01");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_lotacao " +
                     "INNER JOIN ly_funcao " +
                       "ON ly_funcao.funcao = ly_lotacao.funcao " +
                     "INNER JOIN ly_pessoa " +
                       "ON ly_pessoa.pessoa = ly_lotacao.pessoa " +
                     "LEFT JOIN ly_turno " +
                       "ON ly_turno.turno = ly_lotacao.turno " +
                     "LEFT JOIN ly_nucleo " +
                       "ON ly_nucleo.nucleo = ly_lotacao.nucleo " +
                     "LEFT JOIN ly_unidade_ensino " +
                       "ON ly_unidade_ensino.unidade_ens = ly_lotacao.unidade_ens " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_lotacao");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_lotacao");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["PESSOA"] != null && string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                    dr["PESSOA"] = DBNull.Value;
                if (dr["MATRICULA"] != null && string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                    dr["MATRICULA"] = DBNull.Value;
