        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["PESSOA"] == null || string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    return "Favor informar a pessoa.";
                }

                if (dr["PESSOA"] != null && !string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A pessoa deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["MATRICULA"] == null || string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                {
                    return "Favor informar a matrícula.";
                }

                if (dr["MATRICULA"] != null && !string.IsNullOrEmpty(dr["MATRICULA"].ToString()))
                {
                    if (dr["MATRICULA"].ToString().Length > 100)
                    {
                        return "A matrícula deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["ORDEM"] == null || string.IsNullOrEmpty(dr["ORDEM"].ToString()))
                {
                    return "Favor informar o ordem.";
                }

                if (dr["ORDEM"] != null && !string.IsNullOrEmpty(dr["ORDEM"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ORDEM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ORDEM"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["ORDEM"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ORDEM"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ordem deve ser um valor inteiro com 3 dígitos no máximo.";
                    }
                }

                if (dr["FUNCAO"] == null || string.IsNullOrEmpty(dr["FUNCAO"].ToString()))
                {
                    return "Favor informar a funçăo.";
                }

                if (dr["FUNCAO"] != null && !string.IsNullOrEmpty(dr["FUNCAO"].ToString()))
                {
                    if (dr["FUNCAO"].ToString().Length > 20)
                    {
                        return "A funçăo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["TURNO"] != null && !string.IsNullOrEmpty(dr["TURNO"].ToString()))
                {
                    if (dr["TURNO"].ToString().Length > 20)
                    {
                        return "O turno deve possuir no máximo 20 caracteres.";
                    }
                }
                if (dr["DATA_DESATIVACAO"] != null && dr["DATA_DESATIVACAO"].ToString() != "")
                {
                    dr["DATA_DESATIVACAO"] = Convert.ToDateTime(dr["DATA_DESATIVACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["ATO_OFICIAL"] != null && !string.IsNullOrEmpty(dr["ATO_OFICIAL"].ToString()))
                {
                    if (dr["ATO_OFICIAL"].ToString().Length > 100)
                    {
                        return "O ato oficial deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["RESP_DOCUMENTACAO"] != null && !string.IsNullOrEmpty(dr["RESP_DOCUMENTACAO"].ToString()))
                {
                    if (dr["RESP_DOCUMENTACAO"].ToString().Length > 1)
                    {
                        return "O responsável pela documentaçăo deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["UNIDADE_FIS"] != null && !string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                {
                    if (dr["UNIDADE_FIS"].ToString().Length > 20)
                    {
                        return "A unidade física deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DATA_NOMEACAO"] != null && dr["DATA_NOMEACAO"].ToString() != "")
                {
                    dr["DATA_NOMEACAO"] = Convert.ToDateTime(dr["DATA_NOMEACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["DATA_NOMEACAO_DO"] != null && dr["DATA_NOMEACAO_DO"].ToString() != "")
                {
                    dr["DATA_NOMEACAO_DO"] = Convert.ToDateTime(dr["DATA_NOMEACAO_DO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["DATA_DESATIVACAO_DO"] != null && dr["DATA_DESATIVACAO_DO"].ToString() != "")
                {
                    dr["DATA_DESATIVACAO_DO"] = Convert.ToDateTime(dr["DATA_DESATIVACAO_DO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["TIPO_DESATIVACAO"] != null && !string.IsNullOrEmpty(dr["TIPO_DESATIVACAO"].ToString()))
                {
                    if (dr["TIPO_DESATIVACAO"].ToString().Length > 100)
                    {
                        return "O tipo da desativaçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["UNIDADE_ENS"] != null && !string.IsNullOrEmpty(dr["UNIDADE_ENS"].ToString()))
                {
                    if (dr["UNIDADE_ENS"].ToString().Length > 20)
                    {
                        return "A unidade de ensino deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["NUCLEO"] != null && !string.IsNullOrEmpty(dr["NUCLEO"].ToString()))
                {
                    if (dr["NUCLEO"].ToString().Length > 20)
                    {
                        return "O núcleo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["SETOR"] != null && !string.IsNullOrEmpty(dr["SETOR"].ToString()))
                {
                    if (dr["SETOR"].ToString().Length > 15)
                    {
                        return "A unidade administrativa deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["READAPTADO"] != null && !string.IsNullOrEmpty(dr["READAPTADO"].ToString()))
                {
                    if (dr["READAPTADO"].ToString().Length > 1)
                    {
                        return "O readaptado deve possuir no máximo 1 caractere.";
                    }
                }

                if (dr["CATEGORIA"] != null && !string.IsNullOrEmpty(dr["CATEGORIA"].ToString()))
                {
                    if (dr["CATEGORIA"].ToString().Length > 20)
                    {
                        return "A categoria deve possuir no máximo 20 caractere.";
                    }
                }

                if (dr["DT_INICIO_READAPTACAO"] != null && dr["DT_INICIO_READAPTACAO"].ToString() != "")
                {
                    dr["DT_INICIO_READAPTACAO"] = Convert.ToDateTime(dr["DT_INICIO_READAPTACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["DT_FIM_READAPTACAO"] != null && dr["DT_FIM_READAPTACAO"].ToString() != "")
                {
                    dr["DT_FIM_READAPTACAO"] = Convert.ToDateTime(dr["DT_FIM_READAPTACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["MOTIVO_READAPTACAO"] != null && !string.IsNullOrEmpty(dr["MOTIVO_READAPTACAO"].ToString()))
                {
                    if (dr["MOTIVO_READAPTACAO"].ToString().Length > 100)
                    {
                        return "O motivo da readaptaçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["USUARIO"] != null && !string.IsNullOrEmpty(dr["USUARIO"].ToString()))
                {
                    if (dr["USUARIO"].ToString().Length > 15)
                    {
                        return "O Usuario deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["DATA_ATUALIZACAO"] != null && dr["DATA_ATUALIZACAO"].ToString() != "")
                {
                    dr["DATA_ATUALIZACAO"] = Convert.ToDateTime(dr["DATA_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

