        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["MODALIDADE"] != null && string.IsNullOrEmpty(dr["MODALIDADE"].ToString()))
                    dr["MODALIDADE"] = DBNull.Value;
                if (dr["DESCRICAO"] != null && string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                    dr["DESCRICAO"] = DBNull.Value;
                if (dr["CH_MIN"] != null && string.IsNullOrEmpty(dr["CH_MIN"].ToString()))
                    dr["CH_MIN"] = DBNull.Value;
                if (dr["CH_MAX"] != null && string.IsNullOrEmpty(dr["CH_MAX"].ToString()))
                    dr["CH_MAX"] = DBNull.Value;
                if (dr["SISTEMA_AVALIACAO"] != null && string.IsNullOrEmpty(dr["SISTEMA_AVALIACAO"].ToString()))
                    dr["SISTEMA_AVALIACAO"] = DBNull.Value;
                if (dr["TIPO"] != null && string.IsNullOrEmpty(dr["TIPO"].ToString()))
                    dr["TIPO"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["MODALIDADE"] == null || string.IsNullOrEmpty(dr["MODALIDADE"].ToString()))
                {
                    return "Favor informar o sub-nível.";
                }

                if (dr["MODALIDADE"] != null && !string.IsNullOrEmpty(dr["MODALIDADE"].ToString()))
                {
                    if (dr["MODALIDADE"].ToString().Length > 20)
                    {
                        return "O sub-nível deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DESCRICAO"] == null || string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    return "Favor informar a descriçăo.";
                }

                if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    if (dr["DESCRICAO"].ToString().Length > 100)
                    {
                        return "A descriçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["CH_MIN"] != null && !string.IsNullOrEmpty(dr["CH_MIN"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CH_MIN"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CH_MIN"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["CH_MIN"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CH_MIN"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A carga horária mínima deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["CH_MAX"] != null && !string.IsNullOrEmpty(dr["CH_MAX"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["CH_MAX"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CH_MAX"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["CH_MAX"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["CH_MAX"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A carga horária máxima deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["SISTEMA_AVALIACAO"] != null && !string.IsNullOrEmpty(dr["SISTEMA_AVALIACAO"].ToString()))
                {
                    if (dr["SISTEMA_AVALIACAO"].ToString().Length > 20)
                    {
                        return "A sistema de avaliaçăo deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["TIPO"] != null && !string.IsNullOrEmpty(dr["TIPO"].ToString()))
                {
                    if (dr["TIPO"].ToString().Length > 40)
                    {
                        return "O tipo deve possuir no máximo 40 caracteres.";
                    }
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

