        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_nucleo.nucleo"
      });
            if (scColumns.Contains("descricao")) list.Add("ly_nucleo.descricao");
            if (scColumns.Contains("pessoa")) list.Add("ly_nucleo.pessoa");
            if (scColumns.Contains("endereco")) list.Add("ly_nucleo.endereco");
            if (scColumns.Contains("end_num")) list.Add("ly_nucleo.end_num");
            if (scColumns.Contains("end_compl")) list.Add("ly_nucleo.end_compl");
            if (scColumns.Contains("bairro")) list.Add("ly_nucleo.bairro");
            if (scColumns.Contains("cep")) list.Add("ly_nucleo.cep");
            if (scColumns.Contains("municipio")) list.Add("ly_nucleo.municipio");
            if (scColumns.Contains("setor")) list.Add("ly_nucleo.setor");
            if (scColumns.Contains("classificacao")) list.Add("ly_nucleo.classificacao");
            if (scColumns.Contains("fone")) list.Add("ly_nucleo.fone");
            if (scColumns.Contains("e_mail")) list.Add("ly_nucleo.e_mail");
            if (scColumns.Contains("stamp_atualizacao")) list.Add("ly_nucleo.stamp_atualizacao");
            if (scColumns.Contains("nome_compl02")) list.Add("ly_pessoa.nome_compl nome_compl02");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_nucleo " +
                     "INNER JOIN ly_pessoa " +
                       "ON ly_pessoa.pessoa = ly_nucleo.pessoa " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_nucleo");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_nucleo");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["NUCLEO"] != null && string.IsNullOrEmpty(dr["NUCLEO"].ToString()))
                    dr["NUCLEO"] = DBNull.Value;
                if (dr["DESCRICAO"] != null && string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                    dr["DESCRICAO"] = DBNull.Value;
                if (dr["PESSOA"] != null && string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                    dr["PESSOA"] = DBNull.Value;
                if (dr["ENDERECO"] != null && string.IsNullOrEmpty(dr["ENDERECO"].ToString()))
                    dr["ENDERECO"] = DBNull.Value;
                if (dr["END_NUM"] != null && string.IsNullOrEmpty(dr["END_NUM"].ToString()))
                    dr["END_NUM"] = DBNull.Value;
                if (dr["END_COMPL"] != null && string.IsNullOrEmpty(dr["END_COMPL"].ToString()))
                    dr["END_COMPL"] = DBNull.Value;
                if (dr["BAIRRO"] != null && string.IsNullOrEmpty(dr["BAIRRO"].ToString()))
                    dr["BAIRRO"] = DBNull.Value;
                if (dr["CEP"] != null && string.IsNullOrEmpty(dr["CEP"].ToString()))
                    dr["CEP"] = DBNull.Value;
                if (dr["MUNICIPIO"] != null && string.IsNullOrEmpty(dr["MUNICIPIO"].ToString()))
                    dr["MUNICIPIO"] = DBNull.Value;
                if (dr["SETOR"] != null && string.IsNullOrEmpty(dr["SETOR"].ToString()))
                    dr["SETOR"] = DBNull.Value;
                if (dr["CLASSIFICACAO"] != null && string.IsNullOrEmpty(dr["CLASSIFICACAO"].ToString()))
                    dr["CLASSIFICACAO"] = DBNull.Value;
                if (dr["FONE"] != null && string.IsNullOrEmpty(dr["FONE"].ToString()))
                    dr["FONE"] = DBNull.Value;
                if (dr["E_MAIL"] != null && string.IsNullOrEmpty(dr["E_MAIL"].ToString()))
                    dr["E_MAIL"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["NUCLEO"] == null || string.IsNullOrEmpty(dr["NUCLEO"].ToString()))
                {
                    return "Favor informar a coordenadoria.";
                }

                if (dr["NUCLEO"] != null && !string.IsNullOrEmpty(dr["NUCLEO"].ToString()))
                {
                    if (dr["NUCLEO"].ToString().Length > 20)
                    {
                        return "A coordenadoria deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["DESCRICAO"] == null || string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    return "Favor informar a descriçăo.";
                }

                if (dr["DESCRICAO"] != null && !string.IsNullOrEmpty(dr["DESCRICAO"].ToString()))
                {
                    if (dr["DESCRICAO"].ToString().Length > 100)
                    {
                        return "A descriçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["PESSOA"] == null || string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    return "Favor informar a pessoa.";
                }

                if (dr["PESSOA"] != null && !string.IsNullOrEmpty(dr["PESSOA"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[0].Length > 10) || (Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["PESSOA"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "A pessoa deve ser um valor inteiro com 10 dígitos no máximo.";
                    }
                }

                if (dr["ENDERECO"] != null && !string.IsNullOrEmpty(dr["ENDERECO"].ToString()))
                {
                    if (dr["ENDERECO"].ToString().Length > 100)
                    {
                        return "O endereço deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["END_NUM"] != null && !string.IsNullOrEmpty(dr["END_NUM"].ToString()))
                {
                    if (dr["END_NUM"].ToString().Length > 50)
                    {
                        return "O número deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["END_COMPL"] != null && !string.IsNullOrEmpty(dr["END_COMPL"].ToString()))
                {
                    if (dr["END_COMPL"].ToString().Length > 50)
                    {
                        return "O complemento deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["BAIRRO"] != null && !string.IsNullOrEmpty(dr["BAIRRO"].ToString()))
                {
                    if (dr["BAIRRO"].ToString().Length > 50)
                    {
                        return "O bairro deve possuir no máximo 50 caracteres.";
                    }
                }

                if (dr["CEP"] != null && !string.IsNullOrEmpty(dr["CEP"].ToString()))
                {
                    if (dr["CEP"].ToString().Length > 9)
                    {
                        return "O CEP deve possuir no máximo 9 caracteres.";
                    }
                }

                if (dr["MUNICIPIO"] != null && !string.IsNullOrEmpty(dr["MUNICIPIO"].ToString()))
                {
                    if (dr["MUNICIPIO"].ToString().Length > 20)
                    {
                        return "O município deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["SETOR"] != null && !string.IsNullOrEmpty(dr["SETOR"].ToString()))
                {
                    if (dr["SETOR"].ToString().Length > 15)
                    {
                        return "O setor deve possuir no máximo 15 caracteres.";
                    }
                }

                if (dr["CLASSIFICACAO"] != null && !string.IsNullOrEmpty(dr["CLASSIFICACAO"].ToString()))
                {
                    if (dr["CLASSIFICACAO"].ToString().Length > 40)
                    {
                        return "A classificaçăo deve possuir no máximo 40 caracteres.";
                    }
                }

                if (dr["FONE"] != null && !string.IsNullOrEmpty(dr["FONE"].ToString()))
                {
                    if (dr["FONE"].ToString().Length > 30)
                    {
                        return "O telefone deve possuir no máximo 30 caracteres.";
                    }
                }

                if (dr["E_MAIL"] != null && !string.IsNullOrEmpty(dr["E_MAIL"].ToString()))
                {
                    if (dr["E_MAIL"].ToString().Length > 100)
                    {
                        return "O email deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["STAMP_ATUALIZACAO"] != null && dr["STAMP_ATUALIZACAO"].ToString() != "")
                {
                    dr["STAMP_ATUALIZACAO"] = Convert.ToDateTime(dr["STAMP_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
            }
            return "";
        }

        protected override string PreInsert(DataRow row, TConnectionWritable connection)
        {
            ValidaConvEmptyStrToNull(ref row);
            return ValidaCampos(row);
        }

        protected override string PreUpdate(DataRow row, TConnectionWritable connection)
        {
