        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "ano") { result.Add(toLower ? "ano" : column); continue; }
                    if (lower == "periodo") { result.Add(toLower ? "periodo" : column); continue; }
                    if (lower == "subperiodo") { result.Add(toLower ? "subperiodo" : column); continue; }
                    if (lower == "descricao") { result.Add(toLower ? "descricao" : column); continue; }
                    if (lower == "dt_inicio") { result.Add(toLower ? "dt_inicio" : column); continue; }
                    if (lower == "dt_fim") { result.Add(toLower ? "dt_fim" : column); continue; }
                    if (lower == "dias_letivos") { result.Add(toLower ? "dias_letivos" : column); continue; }
                    if (lower == "stamp_atualizacao") { result.Add(toLower ? "stamp_atualizacao" : column); continue; }
                    if (lower == "dt_lancamento") { result.Add(toLower ? "dt_lancamento" : column); continue; }
                    if (lower == "dt_curriculo_minimo") { result.Add(toLower ? "dt_curriculo_minimo" : column); continue; }
                    if (lower == "dt_limite_frequencia") { result.Add(toLower ? "dt_limite_frequencia" : column); continue; }
                    if (!tabPrincipal)
                    {
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "ano", "periodo", "subperiodo", "descricao", "dt_inicio", "dt_fim", 
                                           "dias_letivos", "stamp_atualizacao","dt_lancamento","dt_curriculo_minimo","dt_limite_frequencia" }
                                    : new string[] { "ano", "periodo", "subperiodo", "descricao", "dt_inicio", "dt_fim", 
                                           "dias_letivos", "STAMP_ATUALIZACAO","dt_lancamento","dt_curriculo_minimo","dt_limite_frequencia" });
                else
                    result.AddRange(toLower
                                    ? new string[] { "ano", "periodo", "subperiodo", "descricao", "dt_inicio", "dt_fim", 
                                           "dias_letivos", "stamp_atualizacao","dt_lancamento","dt_curriculo_minimo","dt_limite_frequencia" }
                                    : new string[] { "ano", "periodo", "subperiodo", "descricao", "dt_inicio", "dt_fim", 
                                           "dias_letivos", "STAMP_ATUALIZACAO","dt_lancamento","dt_curriculo_minimo","dt_limite_frequencia" });

            return result;
        }


