        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_subperiodo_letivo.ano", "ly_subperiodo_letivo.periodo", "ly_subperiodo_letivo.subperiodo"
      });
            if (scColumns.Contains("descricao")) list.Add("ly_subperiodo_letivo.descricao");
            if (scColumns.Contains("dt_inicio")) list.Add("ly_subperiodo_letivo.dt_inicio");
            if (scColumns.Contains("dt_fim")) list.Add("ly_subperiodo_letivo.dt_fim");
            if (scColumns.Contains("dias_letivos")) list.Add("ly_subperiodo_letivo.dias_letivos");
            if (scColumns.Contains("stamp_atualizacao")) list.Add("ly_subperiodo_letivo.stamp_atualizacao");
            if (scColumns.Contains("dt_lancamento")) list.Add("ly_subperiodo_letivo.dt_lancamento");
            if (scColumns.Contains("dt_curriculo_minimo")) list.Add("ly_subperiodo_letivo.dt_curriculo_minimo");
            if (scColumns.Contains("dt_limite_frequencia")) list.Add("ly_subperiodo_letivo.dt_limite_frequencia");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_subperiodo_letivo " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_subperiodo_letivo");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
            if (connection == null) throw new ArgumentNullException();

            TDataAdapter da;
            {
                da = new TDataAdapter();
                da.TableMappings.Add("Table", "Ly_subperiodo_letivo");
                da.ContinueUpdateOnError = true;
                da.RowUpdating += new TDataRowUpdateEventHandler(da_RowUpdating);
                da.RowUpdated += new TDataRowUpdateEventHandler(da_RowUpdated);

                da.InsertCommand = CreateCommand(connection, CommandOperation.Insert);
                da.UpdateCommand = CreateCommand(connection, CommandOperation.Update);
                da.DeleteCommand = CreateCommand(connection, CommandOperation.Delete);
            }



            Put(da, connection, dataRows);
        }

        public void ValidaConvEmptyStrToNull(ref DataRow dr)
        {
            if (dr != null)
            {
                if (dr["ano"] != null && string.IsNullOrEmpty(dr["ano"].ToString()))
                    dr["ano"] = DBNull.Value;
                if (dr["periodo"] != null && string.IsNullOrEmpty(dr["periodo"].ToString()))
                    dr["periodo"] = DBNull.Value;
                if (dr["subperiodo"] != null && string.IsNullOrEmpty(dr["subperiodo"].ToString()))
                    dr["subperiodo"] = DBNull.Value;
                if (dr["descricao"] != null && string.IsNullOrEmpty(dr["descricao"].ToString()))
                    dr["descricao"] = DBNull.Value;
                if (dr["dias_letivos"] != null && string.IsNullOrEmpty(dr["dias_letivos"].ToString()))
                    dr["dias_letivos"] = DBNull.Value;
            }
        }

        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["ano"] == null || string.IsNullOrEmpty(dr["ano"].ToString()))
                {
                    return "Favor informar o ano.";
                }

                if (dr["ano"] != null && !string.IsNullOrEmpty(dr["ano"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["ano"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ano"]).ToString("0.############").Split(',')[0].Length > 4) || (Convert.ToDecimal(dr["ano"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["ano"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ano deve ser um valor inteiro com 4 dígitos no máximo.";
                    }
                }

                if (dr["periodo"] == null || string.IsNullOrEmpty(dr["periodo"].ToString()))
                {
                    return "Favor informar o ano letivo.";
                }

                if (dr["periodo"] != null && !string.IsNullOrEmpty(dr["periodo"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["periodo"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["periodo"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["periodo"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["periodo"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O ano letivo deve ser um valor inteiro com 2 dígitos no máximo.";
                    }
                }

                if (dr["subperiodo"] == null || string.IsNullOrEmpty(dr["subperiodo"].ToString()))
                {
                    return "Favor informar o subperíodo letivo.";
                }

                if (dr["subperiodo"] != null && !string.IsNullOrEmpty(dr["subperiodo"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["subperiodo"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["subperiodo"]).ToString("0.############").Split(',')[0].Length > 2) || (Convert.ToDecimal(dr["subperiodo"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["subperiodo"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "O subperíodo letivo deve ser um valor inteiro com 2 dígitos no máximo.";
                    }
                }

                if (dr["descricao"] != null && !string.IsNullOrEmpty(dr["descricao"].ToString()))
                {
                    if (dr["descricao"].ToString().Length > 100)
                    {
                        return "A descriçăo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["dt_inicio"] != null && dr["dt_inicio"].ToString() != "")
                {
                    dr["dt_inicio"] = Convert.ToDateTime(dr["dt_inicio"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["dt_fim"] != null && dr["dt_fim"].ToString() != "")
                {
                    dr["dt_fim"] = Convert.ToDateTime(dr["dt_fim"]).ToString("dd/MM/yyyy HH:mm:ss");
                }

                if (dr["dias_letivos"] != null && !string.IsNullOrEmpty(dr["dias_letivos"].ToString()))
                {
                    if ((Convert.ToDecimal(dr["dias_letivos"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["dias_letivos"]).ToString("0.############").Split(',')[0].Length > 3) || (Convert.ToDecimal(dr["dias_letivos"]).ToString("0.############").Split(',').Length > 1 && Convert.ToDecimal(dr["dias_letivos"]).ToString("0.############").Split(',')[1].Length > 0))
                    {
                        return "Os dias letivos deve ser um valor inteiro com 3 dígitos no máximo.";
                    }
                }

                if (dr["STAMP_ATUALIZACAO"] != null && dr["STAMP_ATUALIZACAO"].ToString() != "")
                {
                    dr["STAMP_ATUALIZACAO"] = Convert.ToDateTime(dr["STAMP_ATUALIZACAO"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
                if (dr["dt_lancamento"] != null && dr["dt_lancamento"].ToString() != "")
                {
                    dr["dt_lancamento"] = Convert.ToDateTime(dr["dt_lancamento"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
                if (dr["dt_curriculo_minimo"] != null && dr["dt_curriculo_minimo"].ToString() != "")
                {
                    dr["dt_curriculo_minimo"] = Convert.ToDateTime(dr["dt_curriculo_minimo"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
                if (dr["dt_limite_frequencia"] != null && dr["dt_limite_frequencia"].ToString() != "")
                {
                    dr["dt_limite_frequencia"] = Convert.ToDateTime(dr["dt_limite_frequencia"]).ToString("dd/MM/yyyy HH:mm:ss");
                }
            }
            return "";
        }

