        public override sealed int Get(TConnection connection,
                                       string[] columns,
                                       string where, DbObject[] whereValues,
                                       string order,
                                       int startRecord,
                                       int maxRecords,
                                       bool createPrimaryKey,
                                       bool getDeletedRecords,
                                       bool rowCountOnly)
        {
            if (where == null) throw new ArgumentNullException("where");
            if (order == null) throw new ArgumentNullException("order");
            TConnection cn = connection != null ? connection : Config.CreateConnection();
            bool sqlServer = cn.Rdbms == Rdbms.SQLServer;
            where = where.Trim();

            int count;

            StringCollection scColumns = FilterColumns(columns, true, false);

            #region Build Select
            ArrayList list = new ArrayList();
            list.AddRange(new string[] {
        "ly_unidade_ensino_notas.id_unidade_ensino_notas"
      });
            if (scColumns.Contains("unidade_ens")) list.Add("ly_unidade_ensino_notas.unidade_ens");
            if (scColumns.Contains("tipo_avaliacao")) list.Add("ly_unidade_ensino_notas.tipo_avaliacao");
            if (scColumns.Contains("curso")) list.Add("ly_unidade_ensino_notas.curso");
            if (scColumns.Contains("turno")) list.Add("ly_unidade_ensino_notas.turno");
            if (scColumns.Contains("curriculo")) list.Add("ly_unidade_ensino_notas.curriculo");
            if (scColumns.Contains("serie")) list.Add("ly_unidade_ensino_notas.serie");
            if (scColumns.Contains("ano")) list.Add("ly_unidade_ensino_notas.ano");
            if (scColumns.Contains("periodo")) list.Add("ly_unidade_ensino_notas.periodo");
            if (scColumns.Contains("tipo_nota")) list.Add("ly_unidade_ensino_notas.tipo_nota");
            if (scColumns.Contains("conceito")) list.Add("ly_unidade_ensino_notas.conceito");
            if (scColumns.Contains("classificacao")) list.Add("ly_unidade_ensino_notas.classificacao");
            if (scColumns.Contains("descricao")) list.Add("ly_serie.descricao");
            string select, columnList, orderby;
            if (rowCountOnly)
            {
                columnList = "count(*)";
                orderby = "";
            }
            else
            {
                columnList = StrLib.EnumerableToStr(list, ", ");
                orderby = (order.Trim().Length == 0 ? string.Empty : " ORDER BY " + order);
            }
            select =
              "SELECT " + columnList + " " +
                "FROM ly_unidade_ensino_notas " +
                     "INNER JOIN ly_serie " +
                       "ON ly_serie.curriculo = ly_unidade_ensino_notas.curriculo AND " +
                          "ly_serie.curso = ly_unidade_ensino_notas.curso AND " +
                          "ly_serie.serie = ly_unidade_ensino_notas.serie AND " +
                          "ly_serie.turno = ly_unidade_ensino_notas.turno " +
                (where.Length == 0 ? string.Empty : " WHERE " + where) +
                orderby;

            #endregion
            if (rowCountOnly)
            {
                #region RowCountOnly
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    try
                    {
                        count = (int)(decimal)cm.ExecuteScalar();
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                          "Select statement: [" + select + "], " +
                          "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }
                #endregion
            }
            else
            {
                #region Fill Datatable
                using (TCommand cm = cn.CreateCommand(select, whereValues))
                {
                    TDataAdapter da = new TDataAdapter(cm);
                    try
                    {
                        DataSet ds = BaseDataSet;
                        bool fakeds = false;
                        if (ds == null)
                        {
                            fakeds = true;
                            ds = new DataSet();
                            ds.Tables.Add(this);
                        }
                        count = da.Fill(ds, startRecord, maxRecords, "ly_unidade_ensino_notas");
                        if (fakeds) ds.Tables.Remove(this);
                    }
                    catch (Exception exc)
                    {
                        throw new Exception(exc.Message + " " +
                                            "Select statement: [" + select + "], " +
                                            "Parameters: [" + StrLib.EnumerableToStr(whereValues) + "]");
                    }
                }

                if (createPrimaryKey) SetPrimaryKey();

                // Cria os nomes (caption) nas colunas da tabela do DataSet
                // de acordo com o idioma informado no construtor da classe.
                foreach (DataColumn dataColumn in Columns)
                {
                    TDataColumn c = dataColumn as TDataColumn;
                    if (c != null && scColumns.Contains(c.ColumnName.ToLower()))
                        c.ReadOnly = c.IsAux;
                }
                #endregion
            }

            return count;
        }

        public override sealed void Put(TConnectionWritable connection, DataRow[] dataRows)
        {
