        public string ValidaCampos(DataRow dr)
        {
            if (dr != null)
            {

                if (dr["UNIDADE_FIS"] == null || string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                {
                    return "Favor informar a unidade física.";
                }

                if (dr["UNIDADE_FIS"] != null && !string.IsNullOrEmpty(dr["UNIDADE_FIS"].ToString()))
                {
                    if (dr["UNIDADE_FIS"].ToString().Length > 20)
                    {
                        return "A unidade física deve possuir no máximo 20 caracteres.";
                    }
                }

                if (dr["NOME_COMP"] == null || string.IsNullOrEmpty(dr["NOME_COMP"].ToString()))
                {
                    return "Favor informar o nome completo.";
                }

                if (dr["NOME_COMP"] != null && !string.IsNullOrEmpty(dr["NOME_COMP"].ToString()))
                {
                    if (dr["NOME_COMP"].ToString().Length > 100)
                    {
                        return "O nome completo deve possuir no máximo 100 caracteres.";
                    }
                }

                if (dr["NOME_ABREV"] != null && !string.IsNullOrEmpty(dr["NOME_ABREV"].ToString()))
                {
                    if (dr["NOME_ABREV"].ToString().Length > 50)
                    {
                        return "O nome abreviado deve possuir no máximo 50 caracteres.";
