        /// <summary>
        /// Filtra o array de colunas retornando somente as colunas pertencentes ao DataTable.
        /// Devolve StringCollection para que seja possível utilizar o método Contains().
        /// </summary>
        /// <param name="toLower">As colunas serăo devolvidas em minúsculas</param>
        /// <param name="tabPrincipal">Somente colunas da tabela principal</param>
        private static StringCollection FilterColumns(string[] columns, bool toLower, bool tabPrincipal)
        {
            StringCollection result = new StringCollection();

            if (columns != null)
                foreach (string column in columns)
                {
                    string lower = column.ToLower();
                    if (lower == "pessoa") { result.Add(toLower ? "pessoa" : column); continue; }
                    if (lower == "ordem") { result.Add(toLower ? "ordem" : column); continue; }
                    if (lower == "matricula") { result.Add(toLower ? "matricula" : column); continue; }
                    if (lower == "data_nomeacao") { result.Add(toLower ? "data_nomeacao" : column); continue; }
                    if (lower == "data_desativacao") { result.Add(toLower ? "data_desativacao" : column); continue; }
                    if (lower == "stamp_atualizacao") { result.Add(toLower ? "stamp_atualizacao" : column); continue; }
                    if (lower == "categoria") { result.Add(toLower ? "categoria" : column); continue; }
                    if (lower == "ch_categoria") { result.Add(toLower ? "ch_categoria" : column); continue; }
                    if (lower == "vinculo") { result.Add(toLower ? "vinculo" : column); continue; }
                    if (lower == "usuarioid") { result.Add(toLower ? "usuarioid" : column); continue; }
                    if (lower == "datacadastro") { result.Add(toLower ? "datacadastro" : column); continue; }
                    if (lower == "dataalteracao") { result.Add(toLower ? "dataalteracao" : column); continue; }

                    if (!tabPrincipal)
                    {
                        if (lower == "idfuncional") { result.Add(toLower ? "idfuncional" : column); continue; }
                    }
                }

            if (result.Count == 0)
                if (tabPrincipal)
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "ordem", "matricula", "data_nomeacao", "data_desativacao", 
                                           "stamp_atualizacao", "categoria", "ch_categoria", "vinculo","usuarioid",
                                            "datacadastro","dataalteracao"
                                           }
                                    : new string[] { "PESSOA", "ORDEM", "MATRICULA", "DATA_NOMEACAO", "DATA_DESATIVACAO", 
                                           "STAMP_ATUALIZACAO", "CATEGORIA", "CH_CATEGORIA" , "VINCULO","USUARIOID",
                                            "DATACADASTRO","DATAALTERACAO"});
                else
                    result.AddRange(toLower
                                    ? new string[] { "pessoa", "ordem", "matricula", "data_nomeacao", "data_desativacao", 
                                           "stamp_atualizacao", "categoria", "ch_categoria", "vinculo","usuarioid",
                                            "datacadastro","dataalteracao" }
                                    : new string[] { "PESSOA", "ORDEM", "MATRICULA", "DATA_NOMEACAO", "DATA_DESATIVACAO", 
                                           "STAMP_ATUALIZACAO", "CATEGORIA", "CH_CATEGORIA", "VINCULO","USUARIOID",
                                            "DATACADASTRO","DATAALTERACAO" });

            return result;
        }


